{
  "name": "TrinaOS Lite",
  "description": "A streamlined AI Executive Assistant for daycare owners to track tasks, finances, and organize thoughts."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppMode {
  DASHBOARD = 'DASHBOARD',
  TASKS = 'TASKS',
  FINANCE = 'FINANCE',
  BRAIN_DUMP = 'BRAIN_DUMP',
  WEEKLY_RESET = 'WEEKLY_RESET',
}

export enum Priority {
  HIGH = 'High',
  MEDIUM = 'Medium',
  LOW = 'Low',
}

export enum TaskStatus {
  TODO = 'Todo',
  DONE = 'Done',
}

export interface Task {
  id: string;
  title: string;
  priority: Priority;
  deadline?: string;
  status: TaskStatus;
  delegatable: boolean;
  createdAt: number;
}

export enum TransactionType {
  INCOME = 'Income',
  EXPENSE = 'Expense',
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  category: string;
  description: string;
  date: string;
  createdAt: number;
}

export interface BrainDumpResult {
  tasks: Partial<Task>[];
  transactions: Partial<Transaction>[];
  analysis: string;
}

export interface WeeklyResetResult {
  summary: string;
  priorities: string[];
}

import { Task, Transaction, TaskStatus, TransactionType, Priority } from '../types';

const STORAGE_KEYS = {
  TASKS: 'trinaos_tasks',
  TRANSACTIONS: 'trinaos_transactions',
  LAST_RESET: 'trinaos_last_reset',
};

// Initial Seed Data
const INITIAL_TASKS: Task[] = [
  {
    id: '1',
    title: 'Renew daycare license',
    priority: Priority.HIGH,
    status: TaskStatus.TODO,
    delegatable: false,
    deadline: new Date(Date.now() + 86400000 * 2).toISOString().split('T')[0],
    createdAt: Date.now(),
  },
  {
    id: '2',
    title: 'Order art supplies',
    priority: Priority.MEDIUM,
    status: TaskStatus.TODO,
    delegatable: true,
    createdAt: Date.now(),
  },
  {
    id: '3',
    title: 'Staff payroll review',
    priority: Priority.HIGH,
    status: TaskStatus.DONE,
    delegatable: false,
    createdAt: Date.now() - 86400000,
  }
];

const INITIAL_TRANSACTIONS: Transaction[] = [
  {
    id: '1',
    type: TransactionType.INCOME,
    amount: 4500,
    category: 'Tuition',
    description: 'Weekly Tuition Batch 1',
    date: new Date().toISOString().split('T')[0],
    createdAt: Date.now(),
  },
  {
    id: '2',
    type: TransactionType.EXPENSE,
    amount: 1200,
    category: 'Rent',
    description: 'Monthly Facility Rent Partial',
    date: new Date().toISOString().split('T')[0],
    createdAt: Date.now(),
  },
  {
    id: '3',
    type: TransactionType.EXPENSE,
    amount: 300,
    category: 'Food',
    description: 'Weekly Snacks',
    date: new Date(Date.now() - 86400000).toISOString().split('T')[0],
    createdAt: Date.now(),
  }
];

export const getTasks = (): Task[] => {
  const stored = localStorage.getItem(STORAGE_KEYS.TASKS);
  if (!stored) {
    localStorage.setItem(STORAGE_KEYS.TASKS, JSON.stringify(INITIAL_TASKS));
    return INITIAL_TASKS;
  }
  return JSON.parse(stored);
};

export const saveTasks = (tasks: Task[]) => {
  localStorage.setItem(STORAGE_KEYS.TASKS, JSON.stringify(tasks));
};

export const addTask = (task: Omit<Task, 'id' | 'createdAt'>) => {
  const tasks = getTasks();
  const newTask: Task = {
    ...task,
    id: crypto.randomUUID(),
    createdAt: Date.now(),
  };
  saveTasks([...tasks, newTask]);
  return newTask;
};

export const updateTask = (updatedTask: Task) => {
  const tasks = getTasks();
  const newTasks = tasks.map(t => t.id === updatedTask.id ? updatedTask : t);
  saveTasks(newTasks);
};

export const getTransactions = (): Transaction[] => {
  const stored = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
  if (!stored) {
    localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(INITIAL_TRANSACTIONS));
    return INITIAL_TRANSACTIONS;
  }
  return JSON.parse(stored);
};

export const saveTransactions = (transactions: Transaction[]) => {
  localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
};

export const addTransaction = (transaction: Omit<Transaction, 'id' | 'createdAt'>) => {
  const transactions = getTransactions();
  const newTransaction: Transaction = {
    ...transaction,
    id: crypto.randomUUID(),
    createdAt: Date.now(),
  };
  saveTransactions([...transactions, newTransaction]);
  return newTransaction;
};

import { GoogleGenAI, Type } from "@google/genai";
import { Task, Transaction, Priority, TaskStatus, TransactionType } from '../types';

// Safely access API key
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const BRAIN_DUMP_SYSTEM_PROMPT = `
You are TrinaOS, an executive assistant for a daycare owner.
Analyze the user's "Brain Dump" text.
Identify tasks and financial transactions.
Extract them into a structured JSON format.
Also provide a short "action plan" summarizing what was added and any immediate advice.

For Tasks:
- Guess priority (High/Medium/Low) based on urgency words.
- Guess deadline if mentioned.
- Default to delegatable: false unless context suggests otherwise.

For Transactions:
- Detect if it's Income or Expense.
- Categorize it (e.g., Supplies, Tuition, Rent, Payroll).
`;

export const processBrainDump = async (text: string): Promise<{
  tasks: any[];
  transactions: any[];
  analysis: string;
}> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: text,
      config: {
        systemInstruction: BRAIN_DUMP_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            tasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  priority: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
                  deadline: { type: Type.STRING, description: "YYYY-MM-DD format if possible, else empty" },
                  delegatable: { type: Type.BOOLEAN }
                }
              }
            },
            transactions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING, enum: ["Income", "Expense"] },
                  amount: { type: Type.NUMBER },
                  category: { type: Type.STRING },
                  description: { type: Type.STRING },
                  date: { type: Type.STRING, description: "YYYY-MM-DD format" }
                }
              }
            },
            analysis: { type: Type.STRING }
          }
        }
      }
    });

    const json = JSON.parse(response.text || '{}');
    return json;
  } catch (error) {
    console.error("Gemini Brain Dump Error:", error);
    throw new Error("Failed to organize brain dump.");
  }
};

const WEEKLY_RESET_SYSTEM_PROMPT = `
You are TrinaOS. Perform a "Weekly CEO Reset" for a daycare owner.
Review the provided financial data and task completion status.
Generate a structured report in Markdown.
Sections:
1. 🏆 Wins of the Week
2. 💰 Financial Snapshot (Revenue, Expenses, Net) & One Optimization Tip
3. ⚠️ Operational/Staff Issues (inferred or general advice if data is sparse)
4. 🌱 Growth Opportunities
5. 🎯 Top 3 Priorities for Next Week
`;

export const generateWeeklyReset = async (
  completedTasks: Task[],
  pendingTasks: Task[],
  transactions: Transaction[]
): Promise<string> => {
  try {
    // Calculate simple financials
    const income = transactions
      .filter(t => t.type === TransactionType.INCOME)
      .reduce((sum, t) => sum + t.amount, 0);
    const expenses = transactions
      .filter(t => t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + t.amount, 0);

    const context = `
      Data for this week:
      Completed Tasks (${completedTasks.length}): ${completedTasks.map(t => t.title).join(', ')}
      Pending High Priority Tasks (${pendingTasks.filter(t => t.priority === Priority.HIGH).length}): ${pendingTasks.filter(t => t.priority === Priority.HIGH).map(t => t.title).join(', ')}

      Financials:
      Total Income: $${income}
      Total Expenses: $${expenses}
      Recent Transactions: ${transactions.slice(0, 5).map(t => `${t.type}: $${t.amount} (${t.category})`).join(', ')}
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: context,
      config: {
        systemInstruction: WEEKLY_RESET_SYSTEM_PROMPT,
      }
    });

    return response.text || "Could not generate report.";
  } catch (error) {
    console.error("Gemini Weekly Reset Error:", error);
    return "Failed to generate weekly reset. Please try again.";
  }
};

