import React from 'react';
import { Task, Transaction, TaskStatus, TransactionType, Priority, AppMode } from '../types';
import { AlertCircle, ArrowUpRight, ArrowDownRight, TrendingUp } from 'lucide-react';

interface DashboardProps {
  tasks: Task[];
  transactions: Transaction[];
  onNavigate: (mode: AppMode) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ tasks, transactions, onNavigate }) => {
  const overdueTasks = tasks.filter(
    t => t.status === TaskStatus.TODO && t.deadline && new Date(t.deadline) < new Date()
  );

  const highPriorityTasks = tasks.filter(
    t => t.status === TaskStatus.TODO && t.priority === Priority.HIGH
  );

  const top3 = highPriorityTasks.slice(0, 3);

  const totalRevenue = transactions
    .filter(t => t.type === TransactionType.INCOME)
    .reduce((sum, t) => sum + t.amount, 0);

  const totalExpenses = transactions
    .filter(t => t.type === TransactionType.EXPENSE)
    .reduce((sum, t) => sum + t.amount, 0);

  const netProfit = totalRevenue - totalExpenses;

  return (
    <div className="p-4 space-y-6 pb-24">
      <header className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Good Morning, Trina.</h1>
        <p className="text-gray-500">Here is your daily command center.</p>
      </header>

      {/* Top 3 Priorities */}
      <section>
        <div className="flex justify-between items-center mb-3">
          <h2 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
            <AlertCircle size={18} className="text-indigo-600" />
            Today's Top 3
          </h2>
          <button 
            onClick={() => onNavigate(AppMode.TASKS)}
            className="text-sm text-indigo-600 font-medium hover:underline"
          >
            View All
          </button>
        </div>
        <div className="space-y-3">
          {top3.length > 0 ? (
            top3.map(task => (
              <div key={task.id} className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex items-start justify-between">
                <div>
                  <h3 className="font-medium text-gray-900">{task.title}</h3>
                  {task.deadline && (
                    <p className="text-xs text-red-500 mt-1 font-medium">Due: {task.deadline}</p>
                  )}
                </div>
                <span className="px-2 py-1 bg-red-100 text-red-700 text-xs rounded-md font-bold uppercase">
                  High
                </span>
              </div>
            ))
          ) : (
            <div className="p-6 bg-white rounded-xl text-center text-gray-400 border border-gray-100 border-dashed">
              No high priority tasks. Great job!
            </div>
          )}
        </div>
      </section>

      {/* Financial Snapshot */}
      <section>
        <div className="flex justify-between items-center mb-3">
          <h2 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
            <TrendingUp size={18} className="text-green-600" />
            Financial Snapshot
          </h2>
          <button 
            onClick={() => onNavigate(AppMode.FINANCE)}
            className="text-sm text-indigo-600 font-medium hover:underline"
          >
            Details
          </button>
        </div>
        <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 grid grid-cols-3 gap-2">
          <div className="text-center p-2 rounded-lg bg-green-50">
            <div className="text-xs text-green-600 font-medium mb-1">Revenue</div>
            <div className="text-sm font-bold text-green-700">${totalRevenue.toLocaleString()}</div>
          </div>
          <div className="text-center p-2 rounded-lg bg-red-50">
            <div className="text-xs text-red-600 font-medium mb-1">Expense</div>
            <div className="text-sm font-bold text-red-700">${totalExpenses.toLocaleString()}</div>
          </div>
          <div className="text-center p-2 rounded-lg bg-indigo-50">
            <div className="text-xs text-indigo-600 font-medium mb-1">Net</div>
            <div className={`text-sm font-bold ${netProfit >= 0 ? 'text-indigo-700' : 'text-red-700'}`}>
              ${netProfit.toLocaleString()}
            </div>
          </div>
        </div>
      </section>

      {/* Task Counts Grid */}
      <section className="grid grid-cols-2 gap-4">
        <div 
          onClick={() => onNavigate(AppMode.TASKS)}
          className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 cursor-pointer active:scale-95 transition-transform"
        >
          <div className="text-2xl font-bold text-red-600">{overdueTasks.length}</div>
          <div className="text-sm text-gray-500 font-medium">Overdue Tasks</div>
        </div>
        <div 
          onClick={() => onNavigate(AppMode.TASKS)}
          className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 cursor-pointer active:scale-95 transition-transform"
        >
          <div className="text-2xl font-bold text-indigo-600">{tasks.filter(t => t.status === TaskStatus.TODO).length}</div>
          <div className="text-sm text-gray-500 font-medium">Active Tasks</div>
        </div>
      </section>

      {/* Quick Action */}
      <button
        onClick={() => onNavigate(AppMode.BRAIN_DUMP)}
        className="w-full bg-gradient-to-r from-indigo-600 to-violet-600 text-white p-4 rounded-xl shadow-lg flex items-center justify-center gap-2 font-semibold active:opacity-90 transition-opacity"
      >
        <BrainCircuit size={20} />
        Start Brain Dump
      </button>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Task, TaskStatus, Priority } from '../types';
import { Plus, Check, Clock, Trash2, Filter } from 'lucide-react';

interface TasksViewProps {
  tasks: Task[];
  onAddTask: (task: Omit<Task, 'id' | 'createdAt'>) => void;
  onUpdateTask: (task: Task) => void;
}

const TasksView: React.FC<TasksViewProps> = ({ tasks, onAddTask, onUpdateTask }) => {
  const [filter, setFilter] = useState<'all' | 'high' | 'todo'>('todo');
  const [isAdding, setIsAdding] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>(Priority.MEDIUM);

  const filteredTasks = tasks
    .filter(t => {
      if (filter === 'all') return true;
      if (filter === 'todo') return t.status === TaskStatus.TODO;
      if (filter === 'high') return t.priority === Priority.HIGH && t.status === TaskStatus.TODO;
      return true;
    })
    .sort((a, b) => {
      // Sort by status (todo first), then priority (high first)
      if (a.status !== b.status) return a.status === TaskStatus.TODO ? -1 : 1;
      const prioOrder = { [Priority.HIGH]: 0, [Priority.MEDIUM]: 1, [Priority.LOW]: 2 };
      return prioOrder[a.priority] - prioOrder[b.priority];
    });

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;

    onAddTask({
      title: newTaskTitle,
      priority: newTaskPriority,
      status: TaskStatus.TODO,
      delegatable: false,
    });
    setNewTaskTitle('');
    setIsAdding(false);
  };

  const toggleStatus = (task: Task) => {
    onUpdateTask({
      ...task,
      status: task.status === TaskStatus.TODO ? TaskStatus.DONE : TaskStatus.TODO
    });
  };

  return (
    <div className="p-4 pb-24 h-full flex flex-col">
      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Tasks</h1>
        <button 
          onClick={() => setIsAdding(!isAdding)}
          className="p-2 bg-indigo-600 text-white rounded-full shadow-lg active:bg-indigo-700"
        >
          <Plus size={24} />
        </button>
      </header>

      {/* Add Task Quick Form */}
      {isAdding && (
        <form onSubmit={handleAdd} className="bg-white p-4 rounded-xl shadow-md border border-indigo-100 mb-6 animate-fade-in-down">
          <input
            type="text"
            value={newTaskTitle}
            onChange={(e) => setNewTaskTitle(e.target.value)}
            placeholder="What needs to be done?"
            className="w-full text-lg font-medium text-gray-900 placeholder-gray-400 border-none focus:ring-0 p-0 mb-3"
            autoFocus
          />
          <div className="flex justify-between items-center">
            <div className="flex gap-2">
              {(Object.values(Priority) as Priority[]).map((p) => (
                <button
                  key={p}
                  type="button"
                  onClick={() => setNewTaskPriority(p)}
                  className={`px-3 py-1 rounded-full text-xs font-semibold ${
                    newTaskPriority === p
                      ? 'bg-indigo-100 text-indigo-700 border border-indigo-200'
                      : 'bg-gray-100 text-gray-500 border border-transparent'
                  }`}
                >
                  {p}
                </button>
              ))}
            </div>
            <button
              type="submit"
              disabled={!newTaskTitle.trim()}
              className="px-4 py-1.5 bg-indigo-600 text-white text-sm font-semibold rounded-lg disabled:opacity-50"
            >
              Add
            </button>
          </div>
        </form>
      )}

      {/* Filters */}
      <div className="flex gap-2 mb-4 overflow-x-auto no-scrollbar">
        {[
          { id: 'todo', label: 'To Do' },
          { id: 'high', label: 'High Priority' },
          { id: 'all', label: 'All Tasks' },
        ].map((f) => (
          <button
            key={f.id}
            onClick={() => setFilter(f.id as any)}
            className={`px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-colors ${
              filter === f.id
                ? 'bg-gray-900 text-white'
                : 'bg-white text-gray-600 border border-gray-200'
            }`}
          >
            {f.label}
          </button>
        ))}
      </div>

      {/* Task List */}
      <div className="flex-1 space-y-3 overflow-y-auto pb-4 no-scrollbar">
        {filteredTasks.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-gray-400">
            <CheckSquare size={48} className="mb-2 opacity-20" />
            <p>No tasks found.</p>
          </div>
        ) : (
          filteredTasks.map((task) => (
            <div
              key={task.id}
              className={`group flex items-center p-4 bg-white rounded-xl border transition-all ${
                task.status === TaskStatus.DONE
                  ? 'border-gray-100 opacity-60'
                  : 'border-gray-100 shadow-sm hover:border-indigo-200'
              }`}
            >
              <button
                onClick={() => toggleStatus(task)}
                className={`flex-shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center mr-4 transition-colors ${
                  task.status === TaskStatus.DONE
                    ? 'bg-green-500 border-green-500 text-white'
                    : 'border-gray-300 text-transparent hover:border-indigo-400'
                }`}
              >
                <Check size={14} strokeWidth={3} />
              </button>

              <div className="flex-1 min-w-0">
                <p className={`text-base font-medium truncate ${
                  task.status === TaskStatus.DONE ? 'text-gray-500 line-through' : 'text-gray-900'
                }`}>
                  {task.title}
                </p>
                <div className="flex items-center gap-2 mt-1">
                  <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded uppercase ${
                    task.priority === Priority.HIGH ? 'bg-red-100 text-red-600' :
                    task.priority === Priority.MEDIUM ? 'bg-yellow-100 text-yellow-600' :
                    'bg-green-100 text-green-600'
                  }`}>
                    {task.priority}
                  </span>
                  {task.deadline && (
                    <span className="text-xs text-gray-400 flex items-center gap-1">
                      <Clock size={10} /> {task.deadline}
                    </span>
                  )}
                </div>
              </div>

              <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                {/* Could add delete/edit here later */}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

