import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import TasksView from './components/TasksView';
import FinanceView from './components/FinanceView';
import BrainDumpView from './components/BrainDumpView';
import WeeklyResetView from './components/WeeklyResetView';
import { AppMode, Task, Transaction, BrainDumpResult } from './types';
import * as Storage from './services/storageService';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.DASHBOARD);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  // Initialize data
  useEffect(() => {
    setTasks(Storage.getTasks());
    setTransactions(Storage.getTransactions());
  }, []);

  // Handlers for data updates
  const handleAddTask = (task: Omit<Task, 'id' | 'createdAt'>) => {
    const newTask = Storage.addTask(task);
    setTasks(prev => [...prev, newTask]);
  };

  const handleUpdateTask = (updatedTask: Task) => {
    Storage.updateTask(updatedTask);
    setTasks(prev => prev.map(t => t.id === updatedTask.id ? updatedTask : t));
  };

  const handleAddTransaction = (transaction: Omit<Transaction, 'id' | 'createdAt'>) => {
    const newTx = Storage.addTransaction(transaction);
    setTransactions(prev => [...prev, newTx]);
  };

  const handleBrainDumpResults = (result: BrainDumpResult) => {
    // Add generated tasks
    if (result.tasks) {
      result.tasks.forEach(t => {
        if (t.title) {
          handleAddTask({
            title: t.title,
            priority: (t.priority as any) || 'Medium',
            status: 'Todo' as any,
            delegatable: t.delegatable || false,
            deadline: t.deadline
          });
        }
      });
    }

    // Add generated transactions
    if (result.transactions) {
      result.transactions.forEach(t => {
        if (t.amount && t.category) {
          handleAddTransaction({
            amount: t.amount,
            category: t.category,
            type: (t.type as any) || 'Expense',
            description: t.description || t.category,
            date: t.date || new Date().toISOString().split('T')[0]
          });
        }
      });
    }
  };

  const renderView = () => {
    switch (currentMode) {
      case AppMode.DASHBOARD:
        return <Dashboard tasks={tasks} transactions={transactions} onNavigate={setCurrentMode} />;
      case AppMode.TASKS:
        return <TasksView tasks={tasks} onAddTask={handleAddTask} onUpdateTask={handleUpdateTask} />;
      case AppMode.FINANCE:
        return <FinanceView transactions={transactions} onAddTransaction={handleAddTransaction} />;
      case AppMode.BRAIN_DUMP:
        return <BrainDumpView onProcessResults={handleBrainDumpResults} />;
      case AppMode.WEEKLY_RESET:
        return <WeeklyResetView tasks={tasks} transactions={transactions} />;
      default:
        return <Dashboard tasks={tasks} transactions={transactions} onNavigate={setCurrentMode} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col mx-auto max-w-2xl shadow-2xl overflow-hidden relative">
      <main className="flex-1 overflow-hidden relative">
        {renderView()}
      </main>
      <Navigation currentMode={currentMode} onNavigate={setCurrentMode} />
    </div>
  );
};

export default App;

