// Audio Utilities for Gemini Live API

export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function float32ToInt16(float32Array: Float32Array): Int16Array {
  const int16Array = new Int16Array(float32Array.length);
  for (let i = 0; i < float32Array.length; i++) {
    let s = Math.max(-1, Math.min(1, float32Array[i]));
    int16Array[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }
  return int16Array;
}

export async function decodeAudioData(
  base64String: string,
  audioContext: AudioContext
): Promise<AudioBuffer> {
  const uint8Array = base64ToUint8Array(base64String);
  const int16Array = new Int16Array(uint8Array.buffer);

  // Gemini returns raw PCM 24kHz mono
  // We need to convert it to AudioBuffer
  const sampleRate = 24000;
  const channels = 1;
  const frameCount = int16Array.length;

  const audioBuffer = audioContext.createBuffer(channels, frameCount, sampleRate);
  const channelData = audioBuffer.getChannelData(0);

  for (let i = 0; i < frameCount; i++) {
    channelData[i] = int16Array[i] / 32768.0;
  }

  return audioBuffer;
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { arrayBufferToBase64, decodeAudioData, float32ToInt16 } from '../services/audioUtils';
import { Task, Transaction } from '../types';

interface UseLiveProps {
  onToolCall: (name: string, args: any) => Promise<any>;
}

export function useLive({ onToolCall }: UseLiveProps) {
  const [isConnected, setIsConnected] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [volume, setVolume] = useState(0);

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const disconnect = useCallback(async () => {
    if (sessionPromiseRef.current) {
      const session = await sessionPromiseRef.current;
      // There is no explicit close method on the session object in some versions, 
      // but we should clean up our side.
      // If the SDK supports it: session.close();
      sessionPromiseRef.current = null;
    }

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (inputSourceRef.current) {
      inputSourceRef.current.disconnect();
      inputSourceRef.current = null;
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }

    // Stop all playing sources
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch(e) {}
    });
    sourcesRef.current.clear();

    setIsConnected(false);
    setIsSpeaking(false);
    setVolume(0);
  }, []);

  const connect = useCallback(async () => {
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) throw new Error("No API Key");

      // Initialize Audio Context
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      const audioContext = new AudioContextClass({ sampleRate: 24000 }); // Output rate
      audioContextRef.current = audioContext;
      nextStartTimeRef.current = audioContext.currentTime;

      // Initialize GenAI
      const ai = new GoogleGenAI({ apiKey });

      // Define Tools
      const tools = [{
        functionDeclarations: [
          {
            name: "changeView",
            description: "Navigate to a specific view. Use when user wants to see something or you are showing them data.",
            parameters: {
              type: "OBJECT",
              properties: {
                view: { type: "STRING", enum: ["TASKS", "FINANCE", "BRAIN_DUMP", "WEEKLY_RESET", "DASHBOARD"] }
              },
              required: ["view"]
            }
          },
          {
            name: "addTask",
            description: "Add a new task. Ask for priority if not provided.",
            parameters: {
              type: "OBJECT",
              properties: {
                title: { type: "STRING" },
                priority: { type: "STRING", enum: ["High", "Medium", "Low"] },
                deadline: { type: "STRING", description: "YYYY-MM-DD" }
              },
              required: ["title", "priority"]
            }
          },
          {
             name: "addTransaction",
             description: "Add a financial transaction.",
             parameters: {
                type: "OBJECT",
                properties: {
                   type: { type: "STRING", enum: ["Income", "Expense"] },
                   amount: { type: "NUMBER" },
                   category: { type: "STRING" },
                   description: { type: "STRING" }
                },
                required: ["type", "amount", "category"]
             }
          },
          {
            name: "getData",
            description: "Get all current tasks and financial transactions to analyze.",
            parameters: { type: "OBJECT", properties: {} }
          }
        ]
      }];

      // System Instructions
      const systemInstruction = `
You are "TrinaOS Voice", an AI-first Executive Assistant.
Your primary interface is voice. Trina (the user) is speaking to you.
Responses must sound natural, concise, and professional.

Rules:
1. When asked to show something, use "changeView".
2. When asked for a summary, call "getData" first, then summarize verbally.
3. If the user sounds overwhelmed, be calm, reassuring, and brief.
4. "DASHBOARD" view is the main Avatar view.
5. Do not read raw JSON IDs.

Flows:
- Financial Snapshot: Say "Here is your snapshot", use "changeView" to FINANCE, call "getData", then summarize Revenue, Expenses, Net.
- Task Capture: Ask for priority/deadline if missing. Confirm with "Got it".
`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: tools,
          systemInstruction: systemInstruction,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
          }
        },
        callbacks: {
          onopen: async () => {
            console.log("Session opened");
            setIsConnected(true);

            // Setup Input Stream
            try {
              const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
              const inputContext = new AudioContext({ sampleRate: 16000 }); // Input rate must be 16kHz for Gemini usually, or we resample. 
              // Actually Gemini handles standard rates, but let's stick to simple 16k processing

              const source = inputContext.createMediaStreamSource(stream);
              // Use ScriptProcessor for broad compatibility in this demo environment
              const processor = inputContext.createScriptProcessor(4096, 1, 1);

              processor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);

                // Calculate volume for visualizer
                let sum = 0;
                for (let i = 0; i < inputData.length; i++) {
                  sum += inputData[i] * inputData[i];
                }
                setVolume(Math.sqrt(sum / inputData.length));

                // Convert to PCM Int16
                const pcmData = float32ToInt16(inputData);
                const base64Data = arrayBufferToBase64(pcmData.buffer);

                sessionPromise.then(session => {
                  session.sendRealtimeInput({
                    media: {
                      mimeType: "audio/pcm;rate=16000",
                      data: base64Data
                    }
                  });
                });
              };

              source.connect(processor);
              processor.connect(inputContext.destination);

              inputSourceRef.current = source;
              processorRef.current = processor;

            } catch (err) {
              console.error("Mic Error:", err);
            }
          },
          onmessage: async (msg: LiveServerMessage) => {
            // Handle Audio Output
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData && audioContextRef.current) {
               setIsSpeaking(true);
               const ctx = audioContextRef.current;
               const buffer = await decodeAudioData(audioData, ctx);

               const source = ctx.createBufferSource();
               source.buffer = buffer;
               source.connect(ctx.destination);

               // Schedule
               const now = ctx.currentTime;
               // If next time is in past, reset to now
               const start = Math.max(now, nextStartTimeRef.current);
               source.start(start);
               nextStartTimeRef.current = start + buffer.duration;

               sourcesRef.current.add(source);
               source.onended = () => {
                 sourcesRef.current.delete(source);
                 if (sourcesRef.current.size === 0) setIsSpeaking(false);
               };
            }

            // Handle Tool Calls
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                console.log("Tool Call:", fc.name, fc.args);
                const result = await onToolCall(fc.name, fc.args);

                sessionPromise.then(session => {
                  session.sendToolResponse({
                    functionResponses: {
                      id: fc.id,
                      name: fc.name,
                      response: { result: result }
                    }
                  });
                });
              }
            }

            // Handle Interruption (reset queue)
            if (msg.serverContent?.interrupted) {
              console.log("Interrupted");
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
              setIsSpeaking(false);
            }
          },
          onclose: () => {
            console.log("Session closed");
            setIsConnected(false);
          },
          onerror: (err) => {
            console.error("Session error:", err);
            setIsConnected(false);
          }
        }
      });

      sessionPromiseRef.current = sessionPromise;

    } catch (e) {
      console.error("Connect failed", e);
      setIsConnected(false);
    }
  }, [onToolCall]);

  return { connect, disconnect, isConnected, isSpeaking, volume };
}

import React from 'react';
import { Mic, MicOff, BrainCircuit, Activity } from 'lucide-react';

interface VoiceDashboardProps {
