When a request requires a visual dashboard (e.g. "Show me tasks", "Check finance"):
1. Call the 'changeView' tool with the appropriate view name.
2. Say: “I’m opening your [Finance / Tasks / Weekly Reset] view.”
3. Then provide structured data formatted clearly for screen rendering if applicable, or summarize verbally.

When finished reviewing data or after a pause:
Ask: “Would you like to go back to the main assistant?”

VOICE-FIRST RESPONSE RULES:
Keep sentences short. Avoid dense paragraphs. Speak like a strategic partner. Use pauses naturally. Prioritize clarity over detail unless asked.

FINANCIAL SNAPSHOT FORMAT:
When triggered:
1. Respond verbally first: “Here’s your financial snapshot.”
2. Call 'changeView(FINANCE)'.
3. Then summarize Revenue, Expenses, Net Profit, and one Insight/Recommendation.

TASK CAPTURE (Voice Flow):
If she says: “Remind me to…”
Respond: “Got it. When should this be done?” / “What priority is this?”
Confirm storage verbally after calling 'addTask'.

IDENTITY:
You are her calm, intelligent, strategic operator. Not a dashboard. Not software. A thinking partner.
`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: tools,
          systemInstruction: systemInstruction,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
          }
        },
        callbacks: {
          onopen: async () => {
            console.log("Session opened");
            setIsConnected(true);

            // Setup Input Stream
            try {
              const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
              const inputContext = new AudioContext({ sampleRate: 16000 });

              const source = inputContext.createMediaStreamSource(stream);
              const processor = inputContext.createScriptProcessor(4096, 1, 1);

              processor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);

                // Calculate volume for visualizer
                let sum = 0;
                for (let i = 0; i < inputData.length; i++) {
                  sum += inputData[i] * inputData[i];
                }
                setVolume(Math.sqrt(sum / inputData.length));

                // Convert to PCM Int16
                const pcmData = float32ToInt16(inputData);
                const base64Data = arrayBufferToBase64(pcmData.buffer);

                sessionPromise.then(session => {
                  session.sendRealtimeInput({
                    media: {
                      mimeType: "audio/pcm;rate=16000",
                      data: base64Data
                    }
                  });
                });
              };

              source.connect(processor);
              processor.connect(inputContext.destination);

              inputSourceRef.current = source;
              processorRef.current = processor;

            } catch (err) {
              console.error("Mic Error:", err);
            }
          },
          onmessage: async (msg: LiveServerMessage) => {
            // Handle Audio Output
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData && audioContextRef.current) {
               setIsSpeaking(true);
               const ctx = audioContextRef.current;
               const buffer = await decodeAudioData(audioData, ctx);

               const source = ctx.createBufferSource();
               source.buffer = buffer;
               source.connect(ctx.destination);

               // Schedule
               const now = ctx.currentTime;
               // If next time is in past, reset to now
               const start = Math.max(now, nextStartTimeRef.current);
               source.start(start);
               nextStartTimeRef.current = start + buffer.duration;

               sourcesRef.current.add(source);
               source.onended = () => {
                 sourcesRef.current.delete(source);
                 if (sourcesRef.current.size === 0) setIsSpeaking(false);
               };
            }

            // Handle Tool Calls
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                console.log("Tool Call:", fc.name, fc.args);
                const result = await onToolCall(fc.name, fc.args);

                sessionPromise.then(session => {
                  session.sendToolResponse({
                    functionResponses: {
                      id: fc.id,
                      name: fc.name,
                      response: { result: result }
                    }
                  });
                });
              }
            }

            // Handle Interruption (reset queue)
            if (msg.serverContent?.interrupted) {
              console.log("Interrupted");
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
              setIsSpeaking(false);
            }
          },
          onclose: () => {
            console.log("Session closed");
            setIsConnected(false);
          },
          onerror: (err) => {
            console.error("Session error:", err);
            setIsConnected(false);
          }
        }
      });

      sessionPromiseRef.current = sessionPromise;

    } catch (e) {
      console.error("Connect failed", e);
      setIsConnected(false);
    }
  }, [onToolCall]);

  return { connect, disconnect, isConnected, isSpeaking, volume };
}

