import React, { useState } from 'react';
import { Task, TaskStatus, Priority } from '../types';
import { Plus, Check, Clock, ArrowLeft } from 'lucide-react';

interface TasksViewProps {
  tasks: Task[];
  onAddTask: (task: Omit<Task, 'id' | 'createdAt'>) => void;
  onUpdateTask: (task: Task) => void;
  onBack: () => void;
}

const TasksView: React.FC<TasksViewProps> = ({ tasks, onAddTask, onUpdateTask, onBack }) => {
  const [filter, setFilter] = useState<'all' | 'high' | 'todo'>('todo');
  const [isAdding, setIsAdding] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>(Priority.MEDIUM);

  const filteredTasks = tasks
    .filter(t => {
      if (filter === 'all') return true;
      if (filter === 'todo') return t.status === TaskStatus.TODO;
      if (filter === 'high') return t.priority === Priority.HIGH && t.status === TaskStatus.TODO;
      return true;
    })
    .sort((a, b) => {
      if (a.status !== b.status) return a.status === TaskStatus.TODO ? -1 : 1;
      const prioOrder = { [Priority.HIGH]: 0, [Priority.MEDIUM]: 1, [Priority.LOW]: 2 };
      return prioOrder[a.priority] - prioOrder[b.priority];
    });

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    onAddTask({
      title: newTaskTitle,
      priority: newTaskPriority,
      status: TaskStatus.TODO,
      delegatable: false,
    });
    setNewTaskTitle('');
    setIsAdding(false);
  };

  const toggleStatus = (task: Task) => {
    onUpdateTask({
      ...task,
      status: task.status === TaskStatus.TODO ? TaskStatus.DONE : TaskStatus.TODO
    });
  };

  return (
    <div className="h-full flex flex-col bg-gray-50">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-100">
        <div className="flex items-center gap-3">
            <button 
                onClick={onBack}
                className="p-2 -ml-2 text-gray-400 hover:text-gray-900 rounded-full hover:bg-gray-100"
            >
                <ArrowLeft size={24} />
            </button>
            <h1 className="text-xl font-bold text-gray-900">Task Tracker</h1>
        </div>
        <button 
          onClick={() => setIsAdding(!isAdding)}
          className="p-2 bg-indigo-50 text-indigo-600 rounded-full hover:bg-indigo-100"
        >
          <Plus size={24} />
        </button>
      </header>

      {/* Add Task Quick Form */}
      {isAdding && (
        <div className="p-4 bg-white border-b border-gray-100">
            <form onSubmit={handleAdd} className="animate-fade-in-down">
            <input
                type="text"
                value={newTaskTitle}
                onChange={(e) => setNewTaskTitle(e.target.value)}
                placeholder="What needs to be done?"
                className="w-full text-lg font-medium text-gray-900 placeholder-gray-400 border-none focus:ring-0 p-0 mb-3"
                autoFocus
            />
            <div className="flex justify-between items-center">
                <div className="flex gap-2">
                {(Object.values(Priority) as Priority[]).map((p) => (
                    <button
                    key={p}
                    type="button"
                    onClick={() => setNewTaskPriority(p)}
                    className={`px-3 py-1 rounded-full text-xs font-semibold ${
                        newTaskPriority === p
                        ? 'bg-indigo-100 text-indigo-700 border border-indigo-200'
                        : 'bg-gray-100 text-gray-500 border border-transparent'
                    }`}
                    >
                    {p}
                    </button>
                ))}
                </div>
                <button
                type="submit"
                disabled={!newTaskTitle.trim()}
                className="px-4 py-1.5 bg-indigo-600 text-white text-sm font-semibold rounded-lg disabled:opacity-50"
                >
                Add
                </button>
            </div>
            </form>
        </div>
      )}

      {/* Filters */}
      <div className="p-4 pb-0">
        <div className="flex gap-2 overflow-x-auto no-scrollbar">
            {[
            { id: 'todo', label: 'To Do' },
            { id: 'high', label: 'High Priority' },
            { id: 'all', label: 'All Tasks' },
            ].map((f) => (
            <button
                key={f.id}
                onClick={() => setFilter(f.id as any)}
                className={`px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-colors ${
                filter === f.id
                    ? 'bg-gray-900 text-white'
                    : 'bg-white text-gray-600 border border-gray-200'
                }`}
            >
                {f.label}
            </button>
            ))}
        </div>
      </div>

      {/* Task List */}
      <div className="flex-1 space-y-3 overflow-y-auto p-4 no-scrollbar">
        {filteredTasks.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-gray-400">
            <p>No tasks found.</p>
          </div>
        ) : (
          filteredTasks.map((task) => (
            <div
              key={task.id}
              className={`group flex items-center p-4 bg-white rounded-xl border transition-all ${
                task.status === TaskStatus.DONE
                  ? 'border-gray-100 opacity-60'
                  : 'border-gray-100 shadow-sm'
              }`}
            >
              <button
                onClick={() => toggleStatus(task)}
                className={`flex-shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center mr-4 transition-colors ${
                  task.status === TaskStatus.DONE
                    ? 'bg-green-500 border-green-500 text-white'
                    : 'border-gray-300 text-transparent hover:border-indigo-400'
                }`}
              >
                <Check size={14} strokeWidth={3} />
              </button>

              <div className="flex-1 min-w-0">
                <p className={`text-base font-medium truncate ${
                  task.status === TaskStatus.DONE ? 'text-gray-500 line-through' : 'text-gray-900'
                }`}>
                  {task.title}
                </p>
                <div className="flex items-center gap-2 mt-1">
                  <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded uppercase ${
                    task.priority === Priority.HIGH ? 'bg-red-100 text-red-600' :
                    task.priority === Priority.MEDIUM ? 'bg-yellow-100 text-yellow-600' :
                    'bg-green-100 text-green-600'
                  }`}>
                    {task.priority}
                  </span>
                  {task.deadline && (
                    <span className="text-xs text-gray-400 flex items-center gap-1">
                      <Clock size={10} /> {task.deadline}
                    </span>
                  )}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default TasksView;

import React, { useState } from 'react';
import { processBrainDump } from '../services/geminiService';
import { BrainCircuit, ArrowRight, Loader2, CheckCircle2, ArrowLeft, Mic } from 'lucide-react';
import { BrainDumpResult } from '../types';

interface BrainDumpViewProps {
  onProcessResults: (result: BrainDumpResult) => void;
  onBack: () => void;
}

const BrainDumpView: React.FC<BrainDumpViewProps> = ({ onProcessResults, onBack }) => {
  const [text, setText] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<BrainDumpResult | null>(null);

  const handleProcess = async () => {
    if (!text.trim()) return;
    setLoading(true);
    try {
      const data = await processBrainDump(text);
      setResult(data as BrainDumpResult);
      onProcessResults(data as BrainDumpResult);
    } catch (error) {
      alert("Failed to organize thoughts. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const reset = () => {
    setText('');
    setResult(null);
  };

  if (result) {
    return (
      <div className="h-full flex flex-col bg-gray-50">
        <header className="p-4 bg-white border-b border-gray-100">
             <button onClick={onBack} className="text-gray-500 flex items-center gap-2 text-sm font-medium">
                 <ArrowLeft size={16} /> Back
             </button>
        </header>
        <div className="flex-1 overflow-y-auto no-scrollbar p-4">
          <div className="text-center mb-6">
            <div className="inline-flex p-3 bg-green-100 text-green-600 rounded-full mb-3">
              <CheckCircle2 size={32} />
            </div>
            <h2 className="text-xl font-bold text-gray-900">Organized!</h2>
          </div>

          <div className="space-y-4">
            <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 text-indigo-900 text-sm leading-relaxed">
              <span className="font-bold block mb-1">💡 Action Plan:</span>
              {result.analysis}
            </div>

            {/* Show simple list of what was done */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                <p className="text-sm text-gray-500">I have added <strong>{result.tasks.length} tasks</strong> and <strong>{result.transactions.length} transactions</strong> to your system.</p>
            </div>
          </div>

          <button
            onClick={reset}
            className="w-full mt-6 py-3 bg-gray-900 text-white font-semibold rounded-xl"
          >
            Start New Dump
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-gray-50">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-100">
        <div className="flex items-center gap-3">
            <button 
                onClick={onBack}
                className="p-2 -ml-2 text-gray-400 hover:text-gray-900 rounded-full hover:bg-gray-100"
            >
                <ArrowLeft size={24} />
            </button>
            <h1 className="text-xl font-bold text-gray-900 flex items-center gap-2">
                <BrainCircuit className="text-indigo-600" size={24}/>
                Brain Dump
            </h1>
        </div>
      </header>

      <div className="flex-1 p-4 flex flex-col">
        <div className="flex-1 relative bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <textarea
            className="w-full h-full p-4 resize-none text-base text-gray-800 placeholder-gray-300 outline-none"
            placeholder="Just start speaking or typing... Tell me about the leaky sink, the $500 tuition payment from Smith, and that you need to call the license board..."
            value={text}
            onChange={(e) => setText(e.target.value)}
          />
          {/* Visual cue that voice works here too */}
          <div className="absolute bottom-4 right-4 text-gray-300 pointer-events-none">
              <Mic size={24} />
          </div>
        </div>

        <button
            onClick={handleProcess}
            disabled={loading || !text.trim()}
            className="mt-4 w-full py-3 bg-indigo-600 text-white font-bold rounded-xl shadow-lg flex items-center justify-center gap-2 disabled:opacity-50"
        >
            {loading ? <Loader2 className="animate-spin" /> : <>Organize This <ArrowRight size={20} /></>}
        </button>
      </div>
    </div>
  );
};

export default BrainDumpView;

import React, { useState } from 'react';
import { Task, Transaction, TaskStatus } from '../types';
import { generateWeeklyReset } from '../services/geminiService';
import { RotateCw, Sparkles, Loader2, ArrowLeft } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

interface WeeklyResetViewProps {
  tasks: Task[];
  transactions: Transaction[];
  onBack: () => void;
}

const WeeklyResetView: React.FC<WeeklyResetViewProps> = ({ tasks, transactions, onBack }) => {
  const [report, setReport] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleReset = async () => {
    setLoading(true);
    const completed = tasks.filter(t => t.status === TaskStatus.DONE);
    const pending = tasks.filter(t => t.status === TaskStatus.TODO);
    const recentTx = transactions; 

    try {
      const result = await generateWeeklyReset(completed, pending, recentTx);
      setReport(result);
    } catch (e) {
      alert("Error generating report.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="h-full flex flex-col bg-gray-50">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-100">
        <div className="flex items-center gap-3">
            <button 
                onClick={onBack}
                className="p-2 -ml-2 text-gray-400 hover:text-gray-900 rounded-full hover:bg-gray-100"
            >
                <ArrowLeft size={24} />
            </button>
            <h1 className="text-xl font-bold text-gray-900">Weekly CEO Reset</h1>
        </div>
      </header>

      {!report && (
        <div className="flex-1 flex flex-col items-center justify-center text-center space-y-6 p-4">
           <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-4">
             <Sparkles size={40} className="text-indigo-600" />
           </div>
           <div>
             <h3 className="text-lg font-semibold text-gray-900">Ready to wrap up?</h3>
             <p className="text-gray-500 text-sm max-w-xs mx-auto mt-2">
               I will analyze your completed tasks and finances to generate a concise executive summary.
             </p>
           </div>
           <button
            onClick={handleReset}
            disabled={loading}
            className="px-8 py-3 bg-gray-900 text-white font-bold rounded-xl shadow-lg flex items-center gap-2 hover:bg-gray-800 disabled:opacity-70 transition-all"
           >
             {loading ? <Loader2 className="animate-spin" /> : 'Run CEO Reset'}
           </button>
        </div>
      )}

      {report && (
        <div className="flex-1 overflow-y-auto no-scrollbar bg-white p-6">
          <article className="prose prose-sm prose-indigo max-w-none">
            <ReactMarkdown>{report}</ReactMarkdown>
          </article>
          <div className="mt-8 flex justify-center pb-8">
            <button 
              onClick={() => setReport(null)}
              className="text-gray-500 text-sm hover:text-gray-900 underline"
            >
              Close Report
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default WeeklyResetView;

import React, { useState, useEffect, useCallback } from 'react';
import Dashboard from './components/Dashboard';
import TasksView from './components/TasksView';
import FinanceView from './components/FinanceView';
import BrainDumpView from './components/BrainDumpView';
import WeeklyResetView from './components/WeeklyResetView';
import { AppMode, Task, Transaction, BrainDumpResult } from './types';
import * as Storage from './services/storageService';
import { useLive } from './hooks/useLive';
import { BrainCircuit, Activity } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.DASHBOARD);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  // Initialize data
  useEffect(() => {
    setTasks(Storage.getTasks());
    setTransactions(Storage.getTransactions());
  }, []);

  // Handlers for data updates
  const handleAddTask = (task: Omit<Task, 'id' | 'createdAt'>) => {
    const newTask = Storage.addTask(task);
    setTasks(prev => [...prev, newTask]);
    return newTask;
  };

  const handleUpdateTask = (updatedTask: Task) => {
    Storage.updateTask(updatedTask);
    setTasks(prev => prev.map(t => t.id === updatedTask.id ? updatedTask : t));
  };

  const handleAddTransaction = (transaction: Omit<Transaction, 'id' | 'createdAt'>) => {
    const newTx = Storage.addTransaction(transaction);
    setTransactions(prev => [...prev, newTx]);
    return newTx;
  };

  const handleBrainDumpResults = (result: BrainDumpResult) => {
    if (result.tasks) {
      result.tasks.forEach(t => {
        if (t.title) {
          handleAddTask({
            title: t.title,
            priority: (t.priority as any) || 'Medium',
            status: 'Todo' as any,
            delegatable: t.delegatable || false,
            deadline: t.deadline
          });
        }
      });
    }
    if (result.transactions) {
      result.transactions.forEach(t => {
        if (t.amount && t.category) {
          handleAddTransaction({
            amount: t.amount,
            category: t.category,
            type: (t.type as any) || 'Expense',
            description: t.description || t.category,
            date: t.date || new Date().toISOString().split('T')[0]
          });
        }
      });
    }
  };

  // Tool Handler
  const handleToolCall = useCallback(async (name: string, args: any) => {
    console.log("Executing Tool:", name, args);

    if (name === 'changeView') {
      const viewMap: Record<string, AppMode> = {
        'TASKS': AppMode.TASKS,
        'FINANCE': AppMode.FINANCE,
        'BRAIN_DUMP': AppMode.BRAIN_DUMP,
        'WEEKLY_RESET': AppMode.WEEKLY_RESET,
        'DASHBOARD': AppMode.DASHBOARD
      };
      const mode = viewMap[args.view];
      if (mode) {
        setCurrentMode(mode);
        return { success: true, message: `Navigated to ${args.view}` };
      }
      return { success: false, message: "Invalid view" };
    }

    if (name === 'addTask') {
      const newTask = handleAddTask({
        title: args.title,
        priority: args.priority || 'Medium',
        deadline: args.deadline,
        status: 'Todo' as any,
        delegatable: false
      });
      return { success: true, task: newTask };
    }

    if (name === 'addTransaction') {
      const newTx = handleAddTransaction({
        type: args.type,
        amount: args.amount,
        category: args.category,
        description: args.description || args.category,
        date: new Date().toISOString().split('T')[0]
      });
      return { success: true, transaction: newTx };
    }

    if (name === 'getData') {
      return {
        tasks: Storage.getTasks(),
        transactions: Storage.getTransactions()
      };
    }

    return { success: false, message: "Unknown tool" };
  }, []);

  const { connect, disconnect, isConnected, isSpeaking, volume } = useLive({
    onToolCall: handleToolCall
  });

  const toggleVoice = () => {
    if (isConnected) disconnect();
    else connect();
  };

  const handleBackToDashboard = () => setCurrentMode(AppMode.DASHBOARD);

  // Render minimized avatar when not in Dashboard
  const MinimizedAvatar = () => {
    if (!isConnected) return null;
    return (
      <div 
         className="fixed bottom-6 right-6 z-50 transition-all duration-300 transform hover:scale-110 cursor-pointer"
         onClick={handleBackToDashboard}
      >
        <div className={`w-16 h-16 rounded-full flex items-center justify-center shadow-xl border-2 border-white ${isSpeaking ? 'bg-indigo-600 animate-pulse' : 'bg-indigo-500'}`}>
           {isSpeaking ? <Activity className="text-white w-8 h-8" /> : <BrainCircuit className="text-white w-8 h-8" />}
        </div>
      </div>
    );
  };

  const renderContent = () => {
    switch (currentMode) {
      case AppMode.TASKS:
        return <TasksView tasks={tasks} onAddTask={handleAddTask} onUpdateTask={handleUpdateTask} onBack={handleBackToDashboard} />;
      case AppMode.FINANCE:
        return <FinanceView transactions={transactions} onAddTransaction={handleAddTransaction} onBack={handleBackToDashboard} />;
      case AppMode.BRAIN_DUMP:
        return <BrainDumpView onProcessResults={handleBrainDumpResults} onBack={handleBackToDashboard} />;
      case AppMode.WEEKLY_RESET:
        return <WeeklyResetView tasks={tasks} transactions={transactions} onBack={handleBackToDashboard} />;
      default:
        return (
          <Dashboard 
            onNavigate={setCurrentMode}
            isConnected={isConnected}
            isSpeaking={isSpeaking}
            volume={volume}
            onToggleVoice={toggleVoice}
          />
        );
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col mx-auto max-w-2xl shadow-2xl overflow-hidden relative">
      <main className="flex-1 overflow-hidden relative">
        {renderContent()}
      </main>

      {/* Show minimized avatar if connected and not on dashboard */}
      {currentMode !== AppMode.DASHBOARD && <MinimizedAvatar />}
    </div>
  );
};

export default App;

