          {/* Outermost Ring */}
          <div className={`absolute inset-0 m-auto w-[340px] h-[340px] rounded-full border border-gray-50 bg-gray-50/30 transition-all duration-700 ease-out ${isConnected ? 'scale-105 opacity-40' : 'scale-100'}`} />

          {/* Middle Ring */}
