          {/* Active State Animations */}
          {isConnected && (
            <>
               {/* AI Speaking Ripple Effect */}
               {isSpeaking && (
                 <>
                    <div className="absolute inset-0 m-auto w-[140px] h-[140px] rounded-full bg-indigo-50 animate-ping opacity-30" />
                    <div className="absolute inset-0 m-auto w-[240px] h-[240px] rounded-full border border-indigo-100 opacity-50 animate-[pulse_2s_infinite]" />
                 </>
               )}

               {/* User Speaking Feedback Ring */}
               {!isSpeaking && (
                 <div 
                   className="absolute inset-0 m-auto w-[140px] h-[140px] rounded-full bg-indigo-50 opacity-30 transition-transform duration-75 ease-out"
                   style={{ transform: `scale(${userVoiceScale})` }}
                 />
               )}
            </>
          )}

          {/* Core Circle & Icon */}
          <div className={`
              relative z-20 w-32 h-32 rounded-full flex items-center justify-center 
              transition-all duration-500
              ${isConnected 
                ? (isSpeaking 
                    ? 'bg-indigo-600 shadow-xl shadow-indigo-200 scale-110' 
                    : 'bg-white border-2 border-indigo-100 shadow-lg scale-100') 
                : 'bg-gray-50 hover:bg-white hover:shadow-md hover:scale-105'
              }
          `}>
             {isConnected ? (
                isSpeaking ? (
                    // Talking Animation (Waveform)
                    <div className="flex gap-1.5 items-center h-8">
                      <div className="w-1.5 bg-white/90 rounded-full animate-[bounce_1s_infinite_0ms] h-3"></div>
                      <div className="w-1.5 bg-white/90 rounded-full animate-[bounce_1s_infinite_200ms] h-8"></div>
                      <div className="w-1.5 bg-white/90 rounded-full animate-[bounce_1s_infinite_400ms] h-5"></div>
                      <div className="w-1.5 bg-white/90 rounded-full animate-[bounce_1s_infinite_100ms] h-6"></div>
                    </div>
                ) : (
                    // Listening Icon
                    <Mic className={`w-8 h-8 transition-all duration-200 ${volume > 0.01 ? 'text-indigo-600 scale-125' : 'text-gray-400'}`} />
                )
             ) : (
                // Idle Icon (Brain)
                <BrainCircuit className="text-gray-300 w-12 h-12 transition-colors group-hover:text-gray-400" strokeWidth={1.5} />
             )}
          </div>
        </div>

        {/* Text Status */}
        <div className="text-center mt-4 h-20 transition-all duration-300">
           {isConnected ? (
             isSpeaking ? (
                <div className="flex flex-col items-center animate-fade-in">
                    <p className="text-xl font-bold text-gray-900">TrinaOS is speaking</p>
                </div>
             ) : (
               <div className="flex flex-col items-center animate-fade-in">
                   <p className="text-xl font-bold text-gray-900">Listening...</p>
                   <p className="text-sm text-gray-400 mt-1 font-medium">Go ahead, I'm ready.</p>
               </div>
             )
           ) : (
             <div className="animate-fade-in">
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Trina, what do you need?</h1>
                <p className="text-gray-400 font-medium cursor-pointer hover:text-indigo-600 transition-colors" onClick={onToggle}>Tap to talk</p>
             </div>
           )}
        </div>

      </div>
    </div>
  );
};

