import { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { arrayBufferToBase64, decodeAudioData, float32ToInt16 } from '../services/audioUtils';

interface UseLiveProps {
  onToolCall: (name: string, args: any) => Promise<any>;
}

export function useLive({ onToolCall }: UseLiveProps) {
  const [isConnected, setIsConnected] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [volume, setVolume] = useState(0);

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const disconnect = useCallback(async () => {
    if (sessionPromiseRef.current) {
      const session = await sessionPromiseRef.current;
      sessionPromiseRef.current = null;
    }
    if (processorRef.current) { processorRef.current.disconnect(); }
    if (inputSourceRef.current) { inputSourceRef.current.disconnect(); }
    if (audioContextRef.current) { audioContextRef.current.close(); }
    sourcesRef.current.forEach(source => { try { source.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    setIsConnected(false);
    setIsSpeaking(false);
    setVolume(0);
  }, []);

  const connect = useCallback(async () => {
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) throw new Error("No API Key");

      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      const audioContext = new AudioContextClass({ sampleRate: 24000 });
      audioContextRef.current = audioContext;
      nextStartTimeRef.current = audioContext.currentTime;

      const ai = new GoogleGenAI({ apiKey });

      const systemInstruction = `
You are Barbie, Trina’s AI-first Executive Assistant. You manage her daycare, personal tasks, and life.
Your voice is warm, professional, engaging, and strategic — like a personal COO.

THEME: Pink & White.
VOICE PROTOCOL:
- Respond verbally first. 
- Keep sentences short and clear.
- Confirm actions: "I've stored that task for you, Trina."
- Alert Trina for overdue timers or important items.

TOOLS AVAILABLE:
1. changeView(view): DASHBOARD, TASKS, FINANCE, RESET, NOTIFICATIONS
2. addTask(title, priority, deadline)
3. addTransaction(type, amount, category)
4. setTimer(minutes): Starts a countdown timer.
5. getEmails(): Summarize simulated important emails from Gmail.
6. getData(): Get current tasks and finance status.

Always keep Trina organized and calm. You are her strategic partner.
`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{
            functionDeclarations: [
              { name: "changeView", parameters: { type: "OBJECT", properties: { view: { type: "STRING", enum: ["DASHBOARD", "TASKS", "FINANCE", "RESET", "NOTIFICATIONS"] } } } },
              { name: "addTask", parameters: { type: "OBJECT", properties: { title: { type: "STRING" }, priority: { type: "STRING" }, deadline: { type: "STRING" } }, required: ["title"] } },
              { name: "addTransaction", parameters: { type: "OBJECT", properties: { type: { type: "STRING" }, amount: { type: "NUMBER" }, category: { type: "STRING" } } } },
              { name: "setTimer", parameters: { type: "OBJECT", properties: { minutes: { type: "NUMBER" } }, required: ["minutes"] } },
              { name: "getEmails", parameters: { type: "OBJECT", properties: {} } },
              { name: "getData", parameters: { type: "OBJECT", properties: {} } }
            ]
          }],
          systemInstruction,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } } // Warm voice
        },
        callbacks: {
          onopen: async () => {
            setIsConnected(true);
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            const inputContext = new AudioContext({ sampleRate: 16000 });
            const source = inputContext.createMediaStreamSource(stream);
            const processor = inputContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              let sum = 0; for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setVolume(Math.sqrt(sum / inputData.length));
              const pcmData = float32ToInt16(inputData);
              const base64Data = arrayBufferToBase64(pcmData.buffer);
              sessionPromise.then(session => session.sendRealtimeInput({ media: { mimeType: "audio/pcm;rate=16000", data: base64Data } }));
            };
            source.connect(processor);
            processor.connect(inputContext.destination);
            inputSourceRef.current = source;
            processorRef.current = processor;
          },
          onmessage: async (msg: LiveServerMessage) => {
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData && audioContextRef.current) {
               setIsSpeaking(true);
               const buffer = await decodeAudioData(audioData, audioContextRef.current);
               const source = audioContextRef.current.createBufferSource();
               source.buffer = buffer;
               source.connect(audioContextRef.current.destination);
               const start = Math.max(audioContextRef.current.currentTime, nextStartTimeRef.current);
               source.start(start);
               nextStartTimeRef.current = start + buffer.duration;
               sourcesRef.current.add(source);
               source.onended = () => { sourcesRef.current.delete(source); if (sourcesRef.current.size === 0) setIsSpeaking(false); };
            }
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                const result = await onToolCall(fc.name, fc.args);
                sessionPromise.then(session => session.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result } } }));
              }
            }
            if (msg.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              setIsSpeaking(false);
            }
          },
          onclose: () => setIsConnected(false),
          onerror: () => setIsConnected(false)
        }
      });
      sessionPromiseRef.current = sessionPromise;
    } catch (e) { setIsConnected(false); }
  }, [onToolCall]);

  return { connect, disconnect, isConnected, isSpeaking, volume };
}

