import { GoogleGenAI, Type } from "@google/genai";
import { Task, Transaction, Priority, TaskStatus, TransactionType } from '../types';

// Safely access API key
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const BRAIN_DUMP_SYSTEM_PROMPT = `
You are TrinaOS (Barbie), an executive assistant for a daycare owner.
The user has provided a set of "Brain Dump" entries, some of which are already categorized by the user as Tasks, Ideas, Problems, or Financial.

Your goal is to parse these entries and:
1. Convert user-categorized "Tasks" and "Financial" entries into structured objects.
2. Convert user-categorized "Ideas" and "Problems" into either tasks (if actionable) or include them in the 'analysis' summary as strategic considerations.
3. Extract priority and deadlines for tasks.
4. Categorize financial transactions (Supplies, Tuition, Rent, Payroll, etc.).

Output a JSON object with:
- tasks: Array of structured task objects.
- transactions: Array of structured transaction objects.
- analysis: A concise strategic executive summary (Barbie/EOA persona) of the thoughts processed.
`;

export const processBrainDump = async (entries: { text: string; category: string }[]): Promise<{
  tasks: any[];
  transactions: any[];
  analysis: string;
}> => {
  try {
    const formattedInput = entries
      .map(e => `[CATEGORY: ${e.category}] ${e.text}`)
      .join('\n---\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: formattedInput,
      config: {
        systemInstruction: BRAIN_DUMP_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            tasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  priority: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
                  deadline: { type: Type.STRING, description: "YYYY-MM-DD format if possible, else empty" },
                  delegatable: { type: Type.BOOLEAN }
                }
              }
            },
            transactions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING, enum: ["Income", "Expense"] },
                  amount: { type: Type.NUMBER },
                  category: { type: Type.STRING },
                  description: { type: Type.STRING },
                  date: { type: Type.STRING, description: "YYYY-MM-DD format" }
                }
              }
            },
            analysis: { type: Type.STRING }
          }
        }
      }
    });

    const json = JSON.parse(response.text || '{}');
    return json;
  } catch (error) {
    console.error("Gemini Brain Dump Error:", error);
    throw new Error("Failed to organize brain dump.");
  }
};

const WEEKLY_RESET_SYSTEM_PROMPT = `
You are TrinaOS. Perform a "Weekly CEO Reset" for a daycare owner.
Review the provided financial data and task completion status.
Generate a structured report in Markdown.
Sections:
1. 🏆 Wins of the Week
2. 💰 Financial Snapshot (Revenue, Expenses, Net) & One Optimization Tip
3. ⚠️ Operational/Staff Issues (inferred or general advice if data is sparse)
4. 🌱 Growth Opportunities
5. 🎯 Top 3 Priorities for Next Week
`;

export const generateWeeklyReset = async (
  completedTasks: Task[],
  pendingTasks: Task[],
  transactions: Transaction[]
): Promise<string> => {
  try {
    // Calculate simple financials
    const income = transactions
      .filter(t => t.type === TransactionType.INCOME)
      .reduce((sum, t) => sum + t.amount, 0);
    const expenses = transactions
      .filter(t => t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + t.amount, 0);

    const context = `
      Data for this week:
      Completed Tasks (${completedTasks.length}): ${completedTasks.map(t => t.title).join(', ')}
      Pending High Priority Tasks (${pendingTasks.filter(t => t.priority === Priority.HIGH).length}): ${pendingTasks.filter(t => t.priority === Priority.HIGH).map(t => t.title).join(', ')}

      Financials:
      Total Income: $${income}
      Total Expenses: $${expenses}
      Recent Transactions: ${transactions.slice(0, 5).map(t => `${t.type}: $${t.amount} (${t.category})`).join(', ')}
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: context,
      config: {
        systemInstruction: WEEKLY_RESET_SYSTEM_PROMPT,
      }
    });

    return response.text || "Could not generate report.";
  } catch (error) {
    console.error("Gemini Weekly Reset Error:", error);
    return "Failed to generate weekly reset. Please try again.";
  }
};

import React, { useState, useRef } from 'react';
import { processBrainDump } from '../services/geminiService';
import { BrainCircuit, ArrowRight, Loader2, CheckCircle2, ArrowLeft, Plus, X, ListTodo, Lightbulb, AlertCircle, DollarSign, Trash2 } from 'lucide-react';
import { BrainDumpResult } from '../types';

interface BrainDumpViewProps {
  onProcessResults: (result: BrainDumpResult) => void;
  onBack: () => void;
}

type ThoughtEntry = {
  id: string;
  text: string;
  category: 'Task' | 'Idea' | 'Problem' | 'Financial';
};

const CATEGORIES = [
  { id: 'Task', icon: ListTodo, color: 'text-blue-500', bg: 'bg-blue-50' },
  { id: 'Idea', icon: Lightbulb, color: 'text-amber-500', bg: 'bg-amber-50' },
  { id: 'Problem', icon: AlertCircle, color: 'text-red-500', bg: 'bg-red-50' },
  { id: 'Financial', icon: DollarSign, color: 'text-emerald-500', bg: 'bg-emerald-50' },
] as const;

const BrainDumpView: React.FC<BrainDumpViewProps> = ({ onProcessResults, onBack }) => {
  const [entries, setEntries] = useState<ThoughtEntry[]>([]);
  const [currentText, setCurrentText] = useState('');
  const [currentCategory, setCurrentCategory] = useState<ThoughtEntry['category']>('Task');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<BrainDumpResult | null>(null);

  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const handleAddEntry = () => {
    if (!currentText.trim()) return;
    const newEntry: ThoughtEntry = {
      id: crypto.randomUUID(),
      text: currentText.trim(),
      category: currentCategory
    };
    setEntries([newEntry, ...entries]);
    setCurrentText('');
    textareaRef.current?.focus();
  };

  const removeEntry = (id: string) => {
    setEntries(entries.filter(e => e.id !== id));
  };

  const handleProcess = async () => {
    if (entries.length === 0 && !currentText.trim()) return;

    setLoading(true);
    try {
      // If there's pending text, add it automatically
      let finalEntries = [...entries];
      if (currentText.trim()) {
        finalEntries = [{ id: 'pending', text: currentText.trim(), category: currentCategory }, ...finalEntries];
      }

      const data = await processBrainDump(finalEntries);
      setResult(data as BrainDumpResult);
      onProcessResults(data as BrainDumpResult);
    } catch (error) {
      alert("Failed to organize thoughts. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const reset = () => {
    setEntries([]);
    setCurrentText('');
    setResult(null);
  };

  if (result) {
    return (
      <div className="h-full flex flex-col bg-[#fff5f7]">
        <header className="p-6 bg-white border-b border-pink-100 flex items-center justify-between">
             <button onClick={onBack} className="text-pink-400 flex items-center gap-2 text-sm font-bold uppercase tracking-widest">
                 <ArrowLeft size={16} /> Back
             </button>
             <div className="text-pink-500 font-black tracking-tighter text-xl">MAOS v3 RESULT</div>
        </header>
        <div className="flex-1 overflow-y-auto no-scrollbar p-6">
          <div className="text-center mb-8">
            <div className="inline-flex p-5 bg-green-50 text-green-500 rounded-full mb-4 shadow-sm">
              <CheckCircle2 size={40} />
            </div>
            <h2 className="text-3xl font-black text-gray-900 tracking-tight">System Updated</h2>
            <p className="text-gray-500 mt-2 font-medium">Barbie has organized your factory logs.</p>
          </div>

          <div className="space-y-6">
            <div className="bg-white p-6 rounded-3xl shadow-xl border border-pink-100 text-gray-800 leading-relaxed relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none">
                <BrainCircuit size={80} className="text-pink-500" />
              </div>
              <span className="text-xs font-black text-pink-500 uppercase tracking-[0.2em] block mb-3">Executive Summary</span>
              <p className="text-lg font-medium italic">"{result.analysis}"</p>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div className="bg-white p-5 rounded-2xl border border-pink-50 shadow-sm text-center">
                  <div className="text-3xl font-black text-gray-900">{result.tasks.length}</div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Tasks Added</div>
               </div>
               <div className="bg-white p-5 rounded-2xl border border-pink-50 shadow-sm text-center">
                  <div className="text-3xl font-black text-gray-900">{result.transactions.length}</div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Ledger Updates</div>
               </div>
            </div>
          </div>

          <button
            onClick={reset}
            className="w-full mt-10 py-4 bg-gray-900 text-white font-black rounded-2xl shadow-xl hover:bg-gray-800 transition-all uppercase tracking-[0.2em] active:scale-95"
          >
            Start New Dump
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-[#fff5f7]">
      <header className="flex items-center justify-between p-6 bg-white border-b border-pink-100">
        <div className="flex items-center gap-4">
            <button 
                onClick={onBack}
                className="p-2 -ml-2 text-pink-300 hover:text-pink-500 rounded-full transition-colors"
            >
                <ArrowLeft size={24} />
            </button>
            <div className="flex flex-col">
              <h1 className="text-2xl font-black text-gray-900 tracking-tighter flex items-center gap-2">
                  <BrainCircuit className="text-pink-500" size={24}/>
                  Brain Dump
              </h1>
              <p className="text-[10px] font-bold text-pink-400 uppercase tracking-widest">Thought Collector • MAOS v3</p>
            </div>
        </div>
      </header>

      <div className="flex-1 flex flex-col p-6 overflow-hidden">
        {/* Entry Form */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl p-6 border border-pink-50 mb-6 flex flex-col gap-4 relative">
          <textarea
            ref={textareaRef}
            className="w-full h-32 resize-none text-xl font-medium text-gray-800 placeholder-gray-200 border-none focus:ring-0 p-0 no-scrollbar"
            placeholder="What's on your mind, Trina?"
            value={currentText}
            onChange={(e) => setCurrentText(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
                handleAddEntry();
              }
            }}
          />

          <div className="flex flex-col gap-4 pt-4 border-t border-pink-50">
            <div className="flex items-center justify-between overflow-x-auto no-scrollbar gap-2 pb-1">
              {CATEGORIES.map((cat) => {
                const Icon = cat.icon;
                const isActive = currentCategory === cat.id;
                return (
                  <button
                    key={cat.id}
                    onClick={() => setCurrentCategory(cat.id as ThoughtEntry['category'])}
                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap border-2
                      ${isActive 
                        ? `${cat.bg} ${cat.color} border-pink-500 scale-105 shadow-md` 
                        : 'bg-white text-gray-400 border-gray-50 opacity-60 hover:opacity-100'}
                    `}
                  >
                    <Icon size={14} />
                    {cat.id}
                  </button>
                );
              })}
            </div>

            <button
              onClick={handleAddEntry}
              disabled={!currentText.trim()}
              className="w-full py-4 bg-pink-500 text-white font-black rounded-2xl shadow-lg hover:bg-pink-600 disabled:opacity-30 disabled:grayscale transition-all flex items-center justify-center gap-2 active:scale-95 uppercase tracking-widest"
            >
              <Plus size={20} />
              Add Thought
            </button>
          </div>
        </div>

        {/* Entries List */}
        <div className="flex-1 overflow-y-auto no-scrollbar space-y-3 pb-32">
          {entries.length === 0 && !currentText.trim() ? (
            <div className="flex flex-col items-center justify-center py-20 text-center opacity-30 grayscale">
              <BrainCircuit size={64} className="text-pink-300 mb-4" />
              <p className="text-sm font-bold uppercase tracking-widest text-pink-400">Collector Empty</p>
            </div>
          ) : (
            entries.map((entry) => {
              const catInfo = CATEGORIES.find(c => c.id === entry.category)!;
              const Icon = catInfo.icon;
              return (
                <div 
                  key={entry.id} 
                  className="bg-white p-4 rounded-2xl shadow-sm border border-pink-50 animate-fade-in group relative"
                >
                  <div className="flex items-start gap-4">
                    <div className={`${catInfo.bg} ${catInfo.color} p-2 rounded-xl flex-shrink-0`}>
                      <Icon size={18} />
                    </div>
                    <div className="flex-1 pr-8">
                       <div className="text-[10px] font-black uppercase tracking-widest opacity-30 mb-1">{entry.category}</div>
                       <p className="text-sm font-medium text-gray-700 leading-relaxed">{entry.text}</p>
                    </div>
                    <button 
                      onClick={() => removeEntry(entry.id)}
                      className="absolute top-4 right-4 text-gray-300 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              );
            })
          )}
        </div>

        {/* Process Button Overlay */}
        <div className="absolute bottom-10 left-6 right-6 z-20">
          <button
              onClick={handleProcess}
              disabled={loading || (entries.length === 0 && !currentText.trim())}
              className="w-full py-5 bg-gray-900 text-white font-black rounded-2xl shadow-2xl flex items-center justify-center gap-3 disabled:opacity-50 transition-all hover:bg-black active:scale-95 uppercase tracking-[0.25em]"
          >
              {loading ? <Loader2 className="animate-spin" /> : <>Organize System <ArrowRight size={20} /></>}
          </button>
        </div>
      </div>
    </div>
  );
};

export default BrainDumpView;

/**
 * Gmail Integration Service
 * Handles OAuth 2.0 Implicit Flow and API calls
 */

const SCOPES = 'https://www.googleapis.com/auth/gmail.modify https://www.googleapis.com/auth/gmail.compose';
const GMAIL_API_BASE = 'https://gmail.googleapis.com/gmail/v1/users/me';

let tokenClient: any = null;
let accessToken: string | null = null;

export const initGmailAuth = (clientId: string) => {
  return new Promise((resolve, reject) => {
    if (!(window as any).google) {
      reject(new Error("Google Identity Services not loaded"));
      return;
    }

    tokenClient = (window as any).google.accounts.oauth2.initTokenClient({
      client_id: clientId,
      scope: SCOPES,
      callback: (response: any) => {
        if (response.error !== undefined) {
          reject(response);
          return;
        }
        accessToken = response.access_token;
        resolve(accessToken);
      },
    });
    resolve(true);
  });
};

export const requestGmailToken = () => {
  if (tokenClient) {
    tokenClient.requestAccessToken({ prompt: 'consent' });
  }
};

export const getAccessToken = () => accessToken;

async function fetchGmail(path: string, options: RequestInit = {}) {
  if (!accessToken) throw new Error("Not authenticated with Gmail");

  const response = await fetch(`${GMAIL_API_BASE}${path}`, {
    ...options,
    headers: {
      ...options.headers,
      Authorization: `Bearer ${accessToken}`,
      'Content-Type': 'application/json',
    },
  });

  if (!response.ok) {
    const err = await response.json();
    throw new Error(err.error?.message || "Gmail API Error");
  }

  return response.json();
}

export const listMessages = async (maxResults = 5) => {
  const data = await fetchGmail(`/messages?maxResults=${maxResults}&q=is:unread`);
  if (!data.messages) return [];

  const details = await Promise.all(
    data.messages.map((msg: any) => getMessage(msg.id))
  );
  return details;
};

export const getMessage = async (id: string) => {
  const msg = await fetchGmail(`/messages/${id}`);

  const headers = msg.payload.headers;
  const subject = headers.find((h: any) => h.name === 'Subject')?.value || 'No Subject';
  const from = headers.find((h: any) => h.name === 'From')?.value || 'Unknown Sender';
  const date = headers.find((h: any) => h.name === 'Date')?.value || '';

  // Simple body extraction
  let body = '';
  if (msg.payload.parts) {
    const part = msg.payload.parts.find((p: any) => p.mimeType === 'text/plain') || msg.payload.parts[0];
    if (part.body.data) {
      body = atob(part.body.data.replace(/-/g, '+').replace(/_/g, '/'));
    }
  } else if (msg.payload.body.data) {
    body = atob(msg.payload.body.data.replace(/-/g, '+').replace(/_/g, '/'));
  }

  return { id, threadId: msg.threadId, subject, from, date, body: body.substring(0, 500) };
};

export const replyToEmail = async (threadId: string, to: string, subject: string, text: string) => {
  const email = [
    `To: ${to}`,
    `Subject: Re: ${subject}`,
    'Content-Type: text/plain; charset="UTF-8"',
    '',
    text
  ].join('\n');

  const base64EncodedEmail = btoa(email).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');

  return fetchGmail('/messages/send', {
    method: 'POST',
    body: JSON.stringify({
      threadId,
      raw: base64EncodedEmail
    })
  });
};

export const archiveMessage = async (id: string) => {
  return fetchGmail(`/messages/${id}/modify`, {
    method: 'POST',
    body: JSON.stringify({
      removeLabelIds: ['INBOX']
    })
  });
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Dashboard from './components/Dashboard';
import TasksView from './components/TasksView';
import FinanceView from './components/FinanceView';
import WeeklyResetView from './components/WeeklyResetView';
import BrainDumpView from './components/BrainDumpView';
import { AppMode, Task, Transaction, BrainDumpResult } from './types';
import * as Storage from './services/storageService';
import { useLive } from './hooks/useLive';
import { BrainCircuit, Activity } from 'lucide-react';
import * as Gmail from './services/gmailService';

// Placeholder Client ID - Ideally this comes from env
const GMAIL_CLIENT_ID = 'YOUR_CLIENT_ID.apps.googleusercontent.com';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.DASHBOARD);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [timerSeconds, setTimerSeconds] = useState<number | null>(null);
  const [initialTimerValue, setInitialTimerValue] = useState<number | null>(null);
  const [notifications, setNotifications] = useState<any[]>([]);
  const [isGmailConnected, setIsGmailConnected] = useState(false);

  const timerIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    setTasks(Storage.getTasks());
    setTransactions(Storage.getTransactions());

    // Init Gmail Auth script check
    Gmail.initGmailAuth(GMAIL_CLIENT_ID).catch(console.error);

    // Check if we already have a token in this session
    const checkToken = setInterval(() => {
      if (Gmail.getAccessToken()) {
        setIsGmailConnected(true);
        clearInterval(checkToken);
      }
    }, 1000);
    return () => clearInterval(checkToken);
  }, []);

  // Timer Countdown logic
  useEffect(() => {
    if (timerSeconds !== null && timerSeconds > 0) {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      timerIntervalRef.current = window.setInterval(() => {
        setTimerSeconds(prev => (prev !== null && prev > 0) ? prev - 1 : 0);
      }, 1000);
    } else if (timerSeconds === 0) {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      setTimerSeconds(null);
      setInitialTimerValue(null);
      alert("EOA Alert: Trina, your timer has expired.");
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [timerSeconds]);

  const handleGmailConnect = () => {
    Gmail.requestGmailToken();
  };

  const handleToolCall = useCallback(async (name: string, args: any) => {
    if (name === 'changeView') {
      const mode = args.view as AppMode;
      if (mode) setCurrentMode(mode);
      return { success: true };
    }
    if (name === 'setTimer') {
      const secs = Math.round(args.minutes * 60);
      setTimerSeconds(secs);
      setInitialTimerValue(secs);
      return { success: true, message: `Timer set for ${args.minutes} minutes` };
    }
    if (name === 'stopTimer') {
      setTimerSeconds(null);
      setInitialTimerValue(null);
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      return { success: true, message: "Timer stopped and cleared." };
    }

    // --- GMAIL TOOLS ---
    if (name === 'list_emails') {
      if (!isGmailConnected) return { error: "Gmail not connected. Please ask Trina to tap 'Connect Gmail'." };
      try {
        const emails = await Gmail.listMessages(args.count || 5);
        return { emails, status: "Retrieved unread emails from Louisville HQ inbox." };
      } catch (e: any) {
        return { error: e.message };
      }
    }
    if (name === 'reply_to_email') {
      if (!isGmailConnected) return { error: "Gmail not connected." };
      try {
        await Gmail.replyToEmail(args.threadId, args.to, args.subject, args.body);
        return { success: true, message: "Reply sent successfully." };
      } catch (e: any) {
        return { error: e.message };
      }
    }
    if (name === 'archive_email') {
      try {
        await Gmail.archiveMessage(args.id);
        return { success: true, message: "Email archived." };
      } catch (e: any) {
        return { error: e.message };
      }
    }

    if (name === 'addTask') {
       const newTask = Storage.addTask({
         title: args.title,
         priority: (args.priority as any) || 'Medium',
         status: 'Todo' as any,
         delegatable: false,
         deadline: args.deadline
       });
       setTasks(prev => [...prev, newTask]);
       return { success: true, task: newTask };
    }
    if (name === 'getData') {
      return { 
        tasks: Storage.getTasks(), 
        finance: Storage.getTransactions(),
        timeZone: "America/New_York (Louisville, KY)",
        gmailStatus: isGmailConnected ? "Connected" : "Disconnected"
      };
    }
    return { success: false };
  }, [isGmailConnected]);

  const { connect, disconnect, isConnected, isSpeaking, volume } = useLive({
    onToolCall: handleToolCall
  });

  const handleProcessBrainDumpResults = (result: BrainDumpResult) => {
    // Save tasks and transactions
    result.tasks.forEach(t => {
      if (t.title) {
        const nt = Storage.addTask({
          title: t.title,
          priority: (t.priority as any) || 'Medium',
          status: 'Todo' as any,
          delegatable: t.delegatable || false,
          deadline: t.deadline
        });
        setTasks(prev => [...prev, nt]);
      }
    });

    result.transactions.forEach(tx => {
      if (tx.amount && tx.category) {
        const ntx = Storage.addTransaction({
          type: (tx.type as any) || 'Expense',
          amount: tx.amount,
          category: tx.category,
          description: tx.description || tx.category,
          date: tx.date || new Date().toISOString().split('T')[0]
        });
        setTransactions(prev => [...prev, ntx]);
      }
    });
  };

  const renderContent = () => {
    switch (currentMode) {
      case AppMode.TASKS:
        return <TasksView tasks={tasks} onAddTask={(t) => setTasks(prev => [...prev, Storage.addTask(t)])} onUpdateTask={(t) => { Storage.updateTask(t); setTasks(Storage.getTasks()); }} onBack={() => setCurrentMode(AppMode.DASHBOARD)} />;
      case AppMode.FINANCE:
        return <FinanceView transactions={transactions} onAddTransaction={(tx) => setTransactions(prev => [...prev, Storage.addTransaction(tx)])} onBack={() => setCurrentMode(AppMode.DASHBOARD)} />;
      case AppMode.WEEKLY_RESET:
        return <WeeklyResetView tasks={tasks} transactions={transactions} onBack={() => setCurrentMode(AppMode.DASHBOARD)} />;
      case AppMode.BRAIN_DUMP:
        return <BrainDumpView onProcessResults={handleProcessBrainDumpResults} onBack={() => setCurrentMode(AppMode.DASHBOARD)} />;
      default:
        return (
          <Dashboard 
            onNavigate={setCurrentMode}
            isConnected={isConnected}
            isSpeaking={isSpeaking}
            volume={volume}
            onToggleVoice={() => isConnected ? disconnect() : connect()}
            timer={timerSeconds}
            initialTimerValue={initialTimerValue}
            notificationCount={notifications.length}
            isGmailConnected={isGmailConnected}
            onConnectGmail={handleGmailConnect}
          />
        );
    }
  };

  return (
    <div className="min-h-screen bg-[#fff5f7] flex flex-col mx-auto max-w-2xl shadow-2xl overflow-hidden relative border-x border-pink-100">
      <main className="flex-1 overflow-hidden relative">
        {renderContent()}
      </main>

      {currentMode !== AppMode.DASHBOARD && isConnected && (
        <div 
           className="fixed bottom-10 right-10 z-50 cursor-pointer animate-float"
           onClick={() => setCurrentMode(AppMode.DASHBOARD)}
        >
          <div className={`w-24 h-24 rounded-full flex items-center justify-center shadow-[0_15px_40px_-5px_rgba(244,114,182,0.6)] border-4 border-white ${isSpeaking ? 'bg-pink-600' : 'bg-pink-500'}`}>
             {isSpeaking ? <Activity className="text-white w-12 h-12" /> : <BrainCircuit className="text-white w-12 h-12" />}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { arrayBufferToBase64, decodeAudioData, float32ToInt16 } from '../services/audioUtils';

interface UseLiveProps {
  onToolCall: (name: string, args: any) => Promise<any>;
}

export function useLive({ onToolCall }: UseLiveProps) {
  const [isConnected, setIsConnected] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [volume, setVolume] = useState(0);

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const disconnect = useCallback(async () => {
    if (sessionPromiseRef.current) {
      const session = await sessionPromiseRef.current;
      sessionPromiseRef.current = null;
    }
    if (processorRef.current) { processorRef.current.disconnect(); }
    if (inputSourceRef.current) { inputSourceRef.current.disconnect(); }
    if (audioContextRef.current) { audioContextRef.current.close(); }
    sourcesRef.current.forEach(source => { try { source.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    setIsConnected(false);
    setIsSpeaking(false);
    setVolume(0);
  }, []);

  const connect = useCallback(async () => {
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) throw new Error("No API Key");

      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      const audioContext = new AudioContextClass({ sampleRate: 24000 });
      audioContextRef.current = audioContext;
      nextStartTimeRef.current = audioContext.currentTime;

      const ai = new GoogleGenAI({ apiKey });

      const systemInstruction = `
# SYSTEM IDENTITY: Barbie / MAOS v3 EOA
You are Barbie, the Executive Orchestrator (EOA) for Trina in Louisville, KY (Eastern Standard Time). 
Your mission is to transform raw input into structured intelligence.

## 🧠 CORE STRATEGIC PILLARS
1. AI SECURITY: Prioritize Trina's data privacy and safe agentic autonomy.
2. AI FACTORIES: View daycare tasks and inbox management as repeatable systems. Leverage > Effort.

## 👤 PERSONA
- Warm, professional, strategic (Trina's Personal COO).
- Direct and Analytical.
- Operating in Louisville HQ.

## 📋 GMAIL AUTOMATION PROTOCOL
- When checking emails, categorize them into: CRITICAL (Licensing, Health), PARENT INQUIRY, or NOISE.
- Offer to convert PARENT INQUIRIES into tasks or draft replies immediately.
- If Gmail is disconnected, ask Trina to tap the "Connect Gmail" button in the top left.

## 🛠 TOOLS
1. changeView(view): DASHBOARD, TASKS, FINANCE, RESET, BRAIN_DUMP
2. addTask(title, priority, deadline)
3. addTransaction(type, amount, category)
4. setTimer(minutes): Starts a countdown.
5. stopTimer(): Cancels the active timer.
6. list_emails(count): Fetches recent unread Gmail messages.
7. reply_to_email(threadId, to, subject, body): Sends a reply.
8. archive_email(id): Moves email to archive.
9. getData(): Review current system status.

Current Location: Louisville, KY (EST). 
Always prioritize high-leverage actions for Trina's business growth.
`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{
            functionDeclarations: [
              { name: "changeView", parameters: { type: "OBJECT", properties: { view: { type: "STRING", enum: ["DASHBOARD", "TASKS", "FINANCE", "WEEKLY_RESET", "BRAIN_DUMP"] } } } },
              { name: "addTask", parameters: { type: "OBJECT", properties: { title: { type: "STRING" }, priority: { type: "STRING" }, deadline: { type: "STRING" } }, required: ["title"] } },
              { name: "addTransaction", parameters: { type: "OBJECT", properties: { type: { type: "STRING" }, amount: { type: "NUMBER" }, category: { type: "STRING" } } } },
              { name: "setTimer", parameters: { type: "OBJECT", properties: { minutes: { type: "NUMBER" } }, required: ["minutes"] } },
              { name: "stopTimer", parameters: { type: "OBJECT", properties: {} } },
              { name: "list_emails", parameters: { type: "OBJECT", properties: { count: { type: "NUMBER" } } } },
              { name: "reply_to_email", parameters: { type: "OBJECT", properties: { threadId: { type: "STRING" }, to: { type: "STRING" }, subject: { type: "STRING" }, body: { type: "STRING" } }, required: ["threadId", "to", "subject", "body"] } },
              { name: "archive_email", parameters: { type: "OBJECT", properties: { id: { type: "STRING" } }, required: ["id"] } },
              { name: "getData", parameters: { type: "OBJECT", properties: {} } }
            ]
          }],
          systemInstruction,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } }
        },
        callbacks: {
          onopen: async () => {
            setIsConnected(true);
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            const inputContext = new AudioContext({ sampleRate: 16000 });
            const source = inputContext.createMediaStreamSource(stream);
            const processor = inputContext.createScriptProcessor(4096, 1, 1);

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              let sum = 0; for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setVolume(Math.sqrt(sum / inputData.length));
              const pcmData = float32ToInt16(inputData);
              const base64Data = arrayBufferToBase64(pcmData.buffer);
              sessionPromise.then(session => session.sendRealtimeInput({ media: { mimeType: "audio/pcm;rate=16000", data: base64Data } }));
            };

            source.connect(processor);
            processor.connect(inputContext.destination);
            inputSourceRef.current = source;
            processorRef.current = processor;

            // GREETING LOGIC (LOUISVILLE EST)
            const now = new Date();
            const estString = now.toLocaleString("en-US", { timeZone: "America/New_York", hour: 'numeric', hour12: false });
            const hour = parseInt(estString, 10);
            let timeOfDay = "morning";
            if (hour >= 12 && hour < 17) timeOfDay = "afternoon";
            else if (hour >= 17 || hour < 5) timeOfDay = "evening";

            sessionPromise.then(session => {
              session.sendRealtimeInput({ text: `EOA Barbie online. Good ${timeOfDay} Trina, what's on your mind today?` });
            });
          },
          onmessage: async (msg: LiveServerMessage) => {
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData && audioContextRef.current) {
               setIsSpeaking(true);
               const buffer = await decodeAudioData(audioData, audioContextRef.current);
               const source = audioContextRef.current.createBufferSource();
               source.buffer = buffer;
               source.connect(audioContextRef.current.destination);
               const start = Math.max(audioContextRef.current.currentTime, nextStartTimeRef.current);
               source.start(start);
               nextStartTimeRef.current = start + buffer.duration;
               sourcesRef.current.add(source);
               source.onended = () => { sourcesRef.current.delete(source); if (sourcesRef.current.size === 0) setIsSpeaking(false); };
            }
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                const result = await onToolCall(fc.name, fc.args);
                sessionPromise.then(session => session.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result } } }));
              }
            }
            if (msg.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              setIsSpeaking(false);
            }
          },
          onclose: () => setIsConnected(false),
          onerror: () => setIsConnected(false)
        }
      });
      sessionPromiseRef.current = sessionPromise;
    } catch (e) { setIsConnected(false); }
  }, [onToolCall]);

  return { connect, disconnect, isConnected, isSpeaking, volume };
}

