Current Location: Louisville, KY (EST). 
Always prioritize high-leverage actions for Trina's business growth.
`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{
            functionDeclarations: [
              { name: "changeView", parameters: { type: "OBJECT", properties: { view: { type: "STRING", enum: ["DASHBOARD", "TASKS", "FINANCE", "WEEKLY_RESET", "BRAIN_DUMP"] } } } },
              { name: "addTask", parameters: { type: "OBJECT", properties: { title: { type: "STRING" }, priority: { type: "STRING" }, deadline: { type: "STRING" } }, required: ["title"] } },
              { name: "addTransaction", parameters: { type: "OBJECT", properties: { type: { type: "STRING" }, amount: { type: "NUMBER" }, category: { type: "STRING" } } } },
              { name: "setTimer", parameters: { type: "OBJECT", properties: { minutes: { type: "NUMBER" } }, required: ["minutes"] } },
              { name: "stopTimer", parameters: { type: "OBJECT", properties: {} } },
              { name: "list_emails", parameters: { type: "OBJECT", properties: { count: { type: "NUMBER" } } } },
              { name: "reply_to_email", parameters: { type: "OBJECT", properties: { threadId: { type: "STRING" }, to: { type: "STRING" }, subject: { type: "STRING" }, body: { type: "STRING" } }, required: ["threadId", "to", "subject", "body"] } },
              { name: "archive_email", parameters: { type: "OBJECT", properties: { id: { type: "STRING" } }, required: ["id"] } },
              { name: "check_database_health", parameters: { type: "OBJECT", properties: {} } },
              { name: "getData", parameters: { type: "OBJECT", properties: {} } }
            ]
          }],
          systemInstruction,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } }
        },
        callbacks: {
          onopen: async () => {
            setIsConnected(true);
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            const inputContext = new AudioContext({ sampleRate: 16000 });
            const source = inputContext.createMediaStreamSource(stream);
            const processor = inputContext.createScriptProcessor(4096, 1, 1);

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              let sum = 0; for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setVolume(Math.sqrt(sum / inputData.length));
              const pcmData = float32ToInt16(inputData);
              const base64Data = arrayBufferToBase64(pcmData.buffer);
              sessionPromise.then(session => session.sendRealtimeInput({ media: { mimeType: "audio/pcm;rate=16000", data: base64Data } }));
            };

            source.connect(processor);
            processor.connect(inputContext.destination);
            inputSourceRef.current = source;
            processorRef.current = processor;

            // GREETING LOGIC (LOUISVILLE EST)
            const now = new Date();
            const estString = now.toLocaleString("en-US", { timeZone: "America/New_York", hour: 'numeric', hour12: false });
            const hour = parseInt(estString, 10);
            let timeOfDay = "morning";
            if (hour >= 12 && hour < 17) timeOfDay = "afternoon";
            else if (hour >= 17 || hour < 5) timeOfDay = "evening";

            sessionPromise.then(session => {
              session.sendRealtimeInput({ text: `EOA Barbie online. Good ${timeOfDay} Trina, what's on your mind today?` });
            });
          },
          onmessage: async (msg: LiveServerMessage) => {
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData && audioContextRef.current) {
               setIsSpeaking(true);
               const buffer = await decodeAudioData(audioData, audioContextRef.current);
               const source = audioContextRef.current.createBufferSource();
               source.buffer = buffer;
               source.connect(audioContextRef.current.destination);
               const start = Math.max(audioContextRef.current.currentTime, nextStartTimeRef.current);
               source.start(start);
               nextStartTimeRef.current = start + buffer.duration;
               sourcesRef.current.add(source);
               source.onended = () => { sourcesRef.current.delete(source); if (sourcesRef.current.size === 0) setIsSpeaking(false); };
            }
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                const result = await onToolCall(fc.name, fc.args);
                sessionPromise.then(session => session.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result } } }));
              }
            }
            if (msg.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              setIsSpeaking(false);
            }
          },
          onclose: () => setIsConnected(false),
          onerror: () => setIsConnected(false)
        }
      });
      sessionPromiseRef.current = sessionPromise;
    } catch (e) { setIsConnected(false); }
  }, [onToolCall]);

  return { connect, disconnect, isConnected, isSpeaking, volume };
}

