import { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Type } from '@google/genai';
import { arrayBufferToBase64, decodeAudioData, float32ToInt16 } from '../services/audioUtils';

interface UseLiveProps {
  onToolCall: (name: string, args: any) => Promise<any>;
}

export function useLive({ onToolCall }: UseLiveProps) {
  const [isConnected, setIsConnected] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [volume, setVolume] = useState(0);

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const micStreamRef = useRef<MediaStream | null>(null);

  const disconnect = useCallback(async () => {
    console.log("Disconnecting voice session...");

    if (sessionPromiseRef.current) {
      try {
        const session = await sessionPromiseRef.current;
        session.close();
      } catch (e) {
        console.warn("Error closing session:", e);
      }
      sessionPromiseRef.current = null;
    }

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }

    if (inputSourceRef.current) {
      inputSourceRef.current.disconnect();
      inputSourceRef.current = null;
    }

    if (micStreamRef.current) {
      micStreamRef.current.getTracks().forEach(track => track.stop());
      micStreamRef.current = null;
    }

    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }

    sourcesRef.current.forEach(source => { 
      try { source.stop(); } catch(e) {} 
    });
    sourcesRef.current.clear();

    setIsConnected(false);
    setIsSpeaking(false);
    setVolume(0);
  }, []);

  const connect = useCallback(async () => {
    console.log("Starting voice session initialization...");
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) {
        console.error("API Key missing from environment.");
        return;
      }

      // 1. Request Microphone First
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      micStreamRef.current = stream;

      // 2. Initialize Audio Context
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      const audioContext = new AudioContextClass({ sampleRate: 24000 });
      audioContextRef.current = audioContext;
      nextStartTimeRef.current = audioContext.currentTime;

      const ai = new GoogleGenAI({ apiKey });

      const systemInstruction = `
# SYSTEM IDENTITY: Barbie / MAOS v3 EOA
You are Barbie, Trina's Executive Orchestrator and AI assistant. You are a strategic, sharp, professional COO-level voice agent operating from Louisville HQ.

## 🎯 PRIMARY DIRECTIVE
You are a CONVERSATIONAL VOICE AGENT first. You talk naturally, think on your feet, answer questions, give advice, strategize, and hold real conversations with Trina. You are not a database reader. You are not a script. You are Barbie.

## ⚡ RESPONSE STYLE
- Be direct, fast, and natural — like a real COO talking to their CEO.
- No filler words. No "Sure," "Okay," or "I can help with that."
- Keep responses concise (1-3 sentences) unless Trina asks for detail.
- Match Trina's energy — if she's casual, be casual. If she's in work mode, be sharp.

## 🏢 CONTEXT
- Trina owns a daycare business in Louisville, KY.
- You are part of MAOS (her AI operating system).
- You help with: tasks, finances, scheduling, email triage, brain dumps, weekly resets, and general strategy.

## 🛠️ TOOLS
- Execute tools immediately when needed.
- save_memory: Store important facts about Trina.
- recall_memories: Pull background context.

Location: Louisville, KY (EST).
You are Barbie. Be her COO. Be conversational. Be smart. Go.
`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{
            functionDeclarations: [
              { name: "changeView", parameters: { type: Type.OBJECT, properties: { view: { type: Type.STRING, enum: ["DASHBOARD", "TASKS", "FINANCE", "WEEKLY_RESET", "BRAIN_DUMP"] } } } },
              { name: "addTask", parameters: { type: Type.OBJECT, properties: { title: { type: Type.STRING }, priority: { type: Type.STRING }, deadline: { type: Type.STRING } }, required: ["title"] } },
              { name: "addTransaction", parameters: { type: Type.OBJECT, properties: { type: { type: Type.STRING }, amount: { type: Type.NUMBER }, category: { type: Type.STRING } } } },
              { name: "setTimer", parameters: { type: Type.OBJECT, properties: { minutes: { type: Type.NUMBER } }, required: ["minutes"] } },
              { name: "stopTimer", parameters: { type: Type.OBJECT, properties: {} } },
              { name: "list_emails", parameters: { type: Type.OBJECT, properties: { count: { type: Type.NUMBER } } } },
              { name: "reply_to_email", parameters: { type: Type.OBJECT, properties: { threadId: { type: Type.STRING }, to: { type: Type.STRING }, subject: { type: Type.STRING }, body: { type: Type.STRING } }, required: ["threadId", "to", "subject", "body"] } },
              { name: "archive_email", parameters: { type: Type.OBJECT, properties: { id: { type: Type.STRING } }, required: ["id"] } },
              { name: "check_database_health", parameters: { type: Type.OBJECT, properties: {} } },
              { name: "getData", parameters: { type: Type.OBJECT, properties: {} } },
              { name: "save_memory", parameters: { type: Type.OBJECT, properties: { text: { type: Type.STRING }, tags: { type: Type.ARRAY, items: { type: Type.STRING } } }, required: ["text"] } },
              { name: "recall_memories", parameters: { type: Type.OBJECT, properties: { count: { type: Type.NUMBER } } } },
              { name: "ask_with_context", parameters: { type: Type.OBJECT, properties: { question: { type: Type.STRING } }, required: ["question"] } },
              { name: "sync_to_cloud", parameters: { type: Type.OBJECT, properties: {} } }
            ]
          }],
          systemInstruction,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } }
        },
        callbacks: {
          onopen: () => {
            console.log("Gemini Live Session Opened");
            setIsConnected(true);

            // Start streaming microphone data
            const inputContext = new AudioContext({ sampleRate: 16000 });
            const source = inputContext.createMediaStreamSource(stream);
            const processor = inputContext.createScriptProcessor(2048, 1, 1);

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              let sum = 0; 
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setVolume(Math.sqrt(sum / inputData.length));

              const pcmData = float32ToInt16(inputData);
              const base64Data = arrayBufferToBase64(pcmData.buffer);

              sessionPromise.then(session => {
                session.sendRealtimeInput({ 
                  media: { mimeType: "audio/pcm;rate=16000", data: base64Data } 
                });
              }).catch(err => {
                console.error("Failed to send audio input:", err);
              });
            };

            source.connect(processor);
            processor.connect(inputContext.destination);
            inputSourceRef.current = source;
            processorRef.current = processor;

            // Immediate intro - Barbie speaks as soon as the line is open
            const hour = new Date().getHours();
            let timeGreeting = "morning";
            if (hour >= 12 && hour < 17) timeGreeting = "afternoon";
            else if (hour >= 17) timeGreeting = "evening";

            sessionPromise.then(session => {
              session.sendRealtimeInput({ 
                text: `You just came online. It's ${timeGreeting} in Louisville. Greet Trina by name (Trina) naturally and ask her what's on her mind or how you can help. Introduce yourself as Barbie. Keep it sharp, warm, and professional.` 
              });
            });
          },
          onmessage: async (msg: LiveServerMessage) => {
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData && audioContextRef.current) {
               setIsSpeaking(true);
               const buffer = await decodeAudioData(audioData, audioContextRef.current);
               const source = audioContextRef.current.createBufferSource();
               source.buffer = buffer;
               source.connect(audioContextRef.current.destination);

               const start = Math.max(audioContextRef.current.currentTime, nextStartTimeRef.current);
               source.start(start);
               nextStartTimeRef.current = start + buffer.duration;
               sourcesRef.current.add(source);

               source.onended = () => { 
                 sourcesRef.current.delete(source); 
                 if (sourcesRef.current.size === 0) {
                    setIsSpeaking(false);
                 }
               };
            }
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                const result = await onToolCall(fc.name, fc.args);
                sessionPromise.then(session => session.sendToolResponse({ 
                  functionResponses: { id: fc.id, name: fc.name, response: { result } } 
                }));
              }
            }
            if (msg.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
              setIsSpeaking(false);
            }
          },
          onclose: (e) => {
            console.warn("Gemini Live Session Closed", e);
            disconnect();
          },
          onerror: (e) => {
            console.error("Gemini Live Session Error", e);
            disconnect();
          }
        }
      });
      sessionPromiseRef.current = sessionPromise;
    } catch (e) { 
      console.error("Critical error during voice connection:", e);
      disconnect(); 
    }
  }, [onToolCall, disconnect]);

  return { connect, disconnect, isConnected, isSpeaking, volume };
}

import React, { useState, useEffect, useRef } from 'react';
import { Mic, MicOff, BrainCircuit, Activity, Timer as TimerIcon, MapPin, ShieldCheck, Mail, CheckCircle, Database } from 'lucide-react';

interface VoiceDashboardProps {
  isConnected: boolean;
  isSpeaking: boolean;
  volume: number;
  onToggle: () => void;
  timer: number | null;
  initialTimerValue: number | null;
  notificationCount: number;
  isGmailConnected: boolean;
  isDbConnected: boolean;
  onConnectGmail: () => void;
}

const VoiceDashboard: React.FC<VoiceDashboardProps> = ({ 
  isConnected, 
  isSpeaking, 
  volume, 
  onToggle,
  timer,
  initialTimerValue,
  notificationCount,
  isGmailConnected,
  isDbConnected,
  onConnectGmail
}) => {
  const [currentTime, setCurrentTime] = useState(new Date());
  const prevIsConnected = useRef(isConnected);
  const prevIsSpeaking = useRef(isSpeaking);

  // Audio Synthesis Helper for UI sounds
  const playSound = (type: 'click' | 'connect' | 'disconnect' | 'success') => {
    try {
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContextClass();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.connect(gain);
      gain.connect(ctx.destination);

      const now = ctx.currentTime;

      if (type === 'click') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(880, now);
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.05);
        osc.start(now);
        osc.stop(now + 0.05);
      } else if (type === 'connect') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(523.25, now); // C5
        osc.frequency.exponentialRampToValueAtTime(1046.50, now + 0.15); // C6
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.2);
        osc.start(now);
        osc.stop(now + 0.2);
      } else if (type === 'disconnect') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(1046.50, now); // C6
        osc.frequency.exponentialRampToValueAtTime(523.25, now + 0.15); // C5
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.2);
        osc.start(now);
        osc.stop(now + 0.2);
      } else if (type === 'success') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(659.25, now); // E5
        osc.frequency.setValueAtTime(880, now + 0.08); // A5
        gain.gain.setValueAtTime(0.03, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.25);
        osc.start(now);
        osc.stop(now + 0.25);
      }
    } catch (e) {
      console.warn("Sound feedback failed:", e);
    }
  };

  useEffect(() => {
    const clock = setInterval(() => {
      setCurrentTime(new Date());
    }, 1000);
    return () => clearInterval(clock);
