            <div 
              className="absolute inset-0 m-auto w-[200px] h-[200px] rounded-full bg-pink-200/40 transition-fast"
              style={{ transform: `scale(${rippleScale})`, opacity: volume > 0.01 ? 1 : 0 }}
            />
          )}
          {isConnected && isSpeaking && (
            <div className="absolute inset-0 m-auto w-[180px] h-[180px] rounded-full bg-pink-400/20 animate-ping" />
          )}

          {/* Core Orb */}
          <div 
            className={`
              relative z-20 w-44 h-44 rounded-full flex items-center justify-center transition-fast
              ${isConnected 
                ? 'bg-white border-4 border-pink-100 shadow-2xl scale-100' 
                : 'bg-white border border-pink-50 animate-breath pink-shadow'}
            `}
            style={{ 
              transform: isConnected && !isSpeaking ? `scale(${coreScale})` : 'scale(1)',
              boxShadow: isConnected && volume > 0.02 ? `0 0 ${40 + volume * 200}px rgba(236, 72, 153, 0.4)` : ''
            }}
          >
            {isConnected && isSpeaking ? (
              <Activity className="text-pink-500 w-16 h-16 animate-pulse" />
            ) : (
              <div className="relative">
                <BrainCircuit 
                  className={`w-24 h-24 transition-fast ${isConnected && volume > 0.01 ? 'text-pink-500 scale-110' : 'text-pink-100'}`} 
                  strokeWidth={1.2} 
                />
                {!isConnected && (
                  <div className="absolute -top-2 -right-2 w-5 h-5 bg-pink-400 rounded-full animate-pulse border-4 border-white" />
                )}
              </div>
            )}
          </div>
        </div>

        {/* Hero Text */}
        <div className="text-center mb-12 h-24 px-6">
           {!isConnected ? (
             <div className="animate-fade-in">
                <h1 className="text-4xl font-black text-gray-900 tracking-tighter">Trina, what's our focus?</h1>
                <p className="text-pink-400 font-bold text-xs mt-3 uppercase tracking-[0.3em]">System Boot: Online</p>
             </div>
           ) : (
             <div className="animate-fade-in">
                <p className="text-2xl font-black text-gray-900 tracking-tight transition-fast">
                   {isSpeaking ? 'Barbie Active...' : 'Listening...'}
                </p>
                <div className="flex gap-1.5 justify-center mt-6 h-8 items-center">
                  {[0, 1, 2, 3, 4, 5, 6, 7].map((i) => (
                    <div 
                      key={i} 
                      className={`w-2 rounded-full transition-fast bg-pink-400`}
                      style={{ height: isSpeaking ? '32px' : `${10 + (Math.random() * volume * 300)}%`, minHeight: '8px' }}
                    />
                  ))}
                </div>
             </div>
           )}
        </div>

        {/* Large Mic Button */}
        <button
          onClick={handleToggleWithSound}
          className={`
            p-12 rounded-full shadow-[0_20px_60px_-15px_rgba(244,114,182,0.5)] transition-all duration-500 transform active:scale-90 z-30 group relative
            ${isConnected 
              ? 'bg-white border-[3px] border-pink-500 text-pink-500' 
              : 'bg-gradient-to-br from-pink-400 via-rose-500 to-pink-600 text-white hover:scale-105'
            }
          `}
        >
          {isConnected ? <MicOff size={48} strokeWidth={2.5} /> : <Mic size={48} strokeWidth={2.5} />}
          <div className="absolute -inset-4 bg-pink-400/20 rounded-full blur-2xl opacity-0 group-hover:opacity-100 transition-opacity" />
        </button>
      </div>
    </div>
  );
};

export default VoiceDashboard;

import React, { useState, useRef, useEffect } from 'react';
import { processBrainDump } from '../services/geminiService';
import { BrainCircuit, ArrowRight, Loader2, CheckCircle2, ArrowLeft, Plus, X, ListTodo, Lightbulb, AlertCircle, DollarSign, Trash2, Mic, MicOff } from 'lucide-react';
import { BrainDumpResult } from '../types';

interface BrainDumpViewProps {
  onProcessResults: (result: BrainDumpResult) => void;
  onBack: () => void;
}

type ThoughtEntry = {
  id: string;
  text: string;
  category: 'Task' | 'Idea' | 'Problem' | 'Financial';
};

const CATEGORIES = [
  { id: 'Task', icon: ListTodo, color: 'text-blue-500', bg: 'bg-blue-50' },
  { id: 'Idea', icon: Lightbulb, color: 'text-amber-500', bg: 'bg-amber-50' },
  { id: 'Problem', icon: AlertCircle, color: 'text-red-500', bg: 'bg-red-50' },
  { id: 'Financial', icon: DollarSign, color: 'text-emerald-500', bg: 'bg-emerald-50' },
] as const;

const BrainDumpView: React.FC<BrainDumpViewProps> = ({ onProcessResults, onBack }) => {
  const [entries, setEntries] = useState<ThoughtEntry[]>([]);
  const [currentText, setCurrentText] = useState('');
  const [currentCategory, setCurrentCategory] = useState<ThoughtEntry['category']>('Task');
  const [loading, setLoading] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [result, setResult] = useState<BrainDumpResult | null>(null);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    // Initialize Speech Recognition
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.lang = 'en-US';

      recognition.onresult = (event: any) => {
        let interimTranscript = '';
        let finalTranscript = '';

        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          } else {
            interimTranscript += event.results[i][0].transcript;
          }
        }

        // Append to current text or replace if it's a fresh start
        setCurrentText(prev => {
           // We try to avoid double appending if recognition restarts
           return finalTranscript || prev + interimTranscript;
        });
      };

      recognition.onerror = (event: any) => {
        console.error('Speech recognition error', event.error);
        setIsRecording(false);
      };

      recognition.onend = () => {
        // If it was supposed to be recording, restart it (browser timeout protection)
        if (isRecording) recognition.start();
      };

      recognitionRef.current = recognition;
    }

    return () => {
      if (recognitionRef.current) recognitionRef.current.stop();
    };
  }, [isRecording]);

  const toggleRecording = () => {
    if (!recognitionRef.current) {
      alert("Speech recognition is not supported in this browser.");
      return;
    }

    if (isRecording) {
      recognitionRef.current.stop();
      setIsRecording(false);
    } else {
      recognitionRef.current.start();
      setIsRecording(true);
      if (textareaRef.current) textareaRef.current.focus();
    }
  };

  const handleAddEntry = () => {
    if (!currentText.trim()) return;
    const newEntry: ThoughtEntry = {
      id: crypto.randomUUID(),
      text: currentText.trim(),
      category: currentCategory
    };
    setEntries([newEntry, ...entries]);
    setCurrentText('');

    // Stop recording after adding a thought to prevent runaway input
    if (isRecording) {
      recognitionRef.current.stop();
      setIsRecording(false);
    }

    textareaRef.current?.focus();
  };

  const removeEntry = (id: string) => {
    setEntries(entries.filter(e => e.id !== id));
  };

  const handleProcess = async () => {
    if (entries.length === 0 && !currentText.trim()) return;

    setLoading(true);
    try {
      // If there's pending text, add it automatically
      let finalEntries = [...entries];
      if (currentText.trim()) {
        finalEntries = [{ id: 'pending', text: currentText.trim(), category: currentCategory }, ...finalEntries];
      }

      const data = await processBrainDump(finalEntries);
      setResult(data as BrainDumpResult);
      onProcessResults(data as BrainDumpResult);
    } catch (error) {
      alert("Failed to organize thoughts. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const reset = () => {
    setEntries([]);
    setCurrentText('');
    setResult(null);
  };

  if (result) {
    return (
      <div className="h-full flex flex-col bg-[#fff5f7]">
        <header className="p-6 bg-white border-b border-pink-100 flex items-center justify-between">
             <button onClick={onBack} className="text-pink-400 flex items-center gap-2 text-sm font-bold uppercase tracking-widest">
                 <ArrowLeft size={16} /> Back
             </button>
             <div className="text-pink-500 font-black tracking-tighter text-xl">MAOS v3 RESULT</div>
        </header>
        <div className="flex-1 overflow-y-auto no-scrollbar p-6">
          <div className="text-center mb-8">
            <div className="inline-flex p-5 bg-green-50 text-green-500 rounded-full mb-4 shadow-sm">
              <CheckCircle2 size={40} />
            </div>
            <h2 className="text-3xl font-black text-gray-900 tracking-tight">System Updated</h2>
            <p className="text-gray-500 mt-2 font-medium">Barbie has organized your factory logs.</p>
          </div>

          <div className="space-y-6">
            <div className="bg-white p-6 rounded-3xl shadow-xl border border-pink-100 text-gray-800 leading-relaxed relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none">
                <BrainCircuit size={80} className="text-pink-500" />
              </div>
              <span className="text-xs font-black text-pink-500 uppercase tracking-[0.2em] block mb-3">Executive Summary</span>
              <p className="text-lg font-medium italic">"{result.analysis}"</p>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div className="bg-white p-5 rounded-2xl border border-pink-50 shadow-sm text-center">
                  <div className="text-3xl font-black text-gray-900">{result.tasks.length}</div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Tasks Added</div>
               </div>
               <div className="bg-white p-5 rounded-2xl border border-pink-50 shadow-sm text-center">
                  <div className="text-3xl font-black text-gray-900">{result.transactions.length}</div>
                  <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Ledger Updates</div>
               </div>
            </div>
          </div>

          <button
            onClick={reset}
            className="w-full mt-10 py-4 bg-gray-900 text-white font-black rounded-2xl shadow-xl hover:bg-gray-800 transition-all uppercase tracking-[0.2em] active:scale-95"
          >
            Start New Dump
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-[#fff5f7]">
      <header className="flex items-center justify-between p-6 bg-white border-b border-pink-100">
        <div className="flex items-center gap-4">
            <button 
                onClick={onBack}
                className="p-2 -ml-2 text-pink-300 hover:text-pink-500 rounded-full transition-colors"
            >
                <ArrowLeft size={24} />
            </button>
            <div className="flex flex-col">
              <h1 className="text-2xl font-black text-gray-900 tracking-tighter flex items-center gap-2">
                  <BrainCircuit className="text-pink-500" size={24}/>
                  Brain Dump
              </h1>
              <p className="text-[10px] font-bold text-pink-400 uppercase tracking-widest">Thought Collector • MAOS v3</p>
            </div>
        </div>
      </header>

      <div className="flex-1 flex flex-col p-6 overflow-hidden">
        {/* Entry Form */}
        <div className={`bg-white rounded-[2.5rem] shadow-2xl p-6 border transition-all duration-300 mb-6 flex flex-col gap-4 relative
          ${isRecording ? 'border-pink-400 ring-4 ring-pink-50' : 'border-pink-50'}
        `}>
          <div className="relative group">
            <textarea
              ref={textareaRef}
              className="w-full h-32 resize-none text-xl font-medium text-gray-800 placeholder-gray-200 border-none focus:ring-0 p-0 no-scrollbar pr-12"
              placeholder={isRecording ? "Listening to your thoughts..." : "What's on your mind, Trina?"}
              value={currentText}
              onChange={(e) => setCurrentText(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
                  handleAddEntry();
                }
              }}
            />

            {/* Voice Trigger Icon inside Textarea area */}
            <button 
              onClick={toggleRecording}
              className={`absolute top-0 right-0 p-3 rounded-full transition-all active:scale-95
                ${isRecording ? 'bg-pink-500 text-white animate-pulse' : 'bg-pink-50 text-pink-400 hover:bg-pink-100'}
              `}
            >
              {isRecording ? <MicOff size={20} /> : <Mic size={20} />}
            </button>
          </div>

          <div className="flex flex-col gap-4 pt-4 border-t border-pink-50">
            <div className="flex items-center justify-between overflow-x-auto no-scrollbar gap-2 pb-1">
              {CATEGORIES.map((cat) => {
                const Icon = cat.icon;
                const isActive = currentCategory === cat.id;
                return (
                  <button
                    key={cat.id}
                    onClick={() => setCurrentCategory(cat.id as ThoughtEntry['category'])}
                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap border-2
                      ${isActive 
                        ? `${cat.bg} ${cat.color} border-pink-500 scale-105 shadow-md` 
                        : 'bg-white text-gray-400 border-gray-50 opacity-60 hover:opacity-100'}
                    `}
                  >
                    <Icon size={14} />
                    {cat.id}
                  </button>
                );
              })}
            </div>

            <button
              onClick={handleAddEntry}
              disabled={!currentText.trim()}
              className="w-full py-4 bg-pink-500 text-white font-black rounded-2xl shadow-lg hover:bg-pink-600 disabled:opacity-30 disabled:grayscale transition-all flex items-center justify-center gap-2 active:scale-95 uppercase tracking-widest"
            >
              <Plus size={20} />
              Add Thought
            </button>
          </div>
        </div>

        {/* Entries List */}
        <div className="flex-1 overflow-y-auto no-scrollbar space-y-3 pb-32">
          {entries.length === 0 && !currentText.trim() ? (
            <div className="flex flex-col items-center justify-center py-20 text-center opacity-30 grayscale">
              <BrainCircuit size={64} className="text-pink-300 mb-4" />
              <p className="text-sm font-bold uppercase tracking-widest text-pink-400">Collector Empty</p>
            </div>
          ) : (
            entries.map((entry) => {
              const catInfo = CATEGORIES.find(c => c.id === entry.category)!;
              const Icon = catInfo.icon;
              return (
                <div 
                  key={entry.id} 
                  className="bg-white p-4 rounded-2xl shadow-sm border border-pink-50 animate-fade-in group relative"
                >
                  <div className="flex items-start gap-4">
                    <div className={`${catInfo.bg} ${catInfo.color} p-2 rounded-xl flex-shrink-0`}>
                      <Icon size={18} />
                    </div>
                    <div className="flex-1 pr-8">
                       <div className="text-[10px] font-black uppercase tracking-widest opacity-30 mb-1">{entry.category}</div>
                       <p className="text-sm font-medium text-gray-700 leading-relaxed">{entry.text}</p>
                    </div>
                    <button 
                      onClick={() => removeEntry(entry.id)}
                      className="absolute top-4 right-4 text-gray-300 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              );
            })
          )}
        </div>

        {/* Process Button Overlay */}
        <div className="absolute bottom-10 left-6 right-6 z-20">
          <button
              onClick={handleProcess}
              disabled={loading || (entries.length === 0 && !currentText.trim())}
              className="w-full py-5 bg-gray-900 text-white font-black rounded-2xl shadow-2xl flex items-center justify-center gap-3 disabled:opacity-50 transition-all hover:bg-black active:scale-95 uppercase tracking-[0.25em]"
          >
              {loading ? <Loader2 className="animate-spin" /> : <>Organize System <ArrowRight size={20} /></>}
          </button>
        </div>
      </div>
    </div>
  );
};

export default BrainDumpView;

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Upload, FileText, Trash2, Search, Loader2, CheckCircle, AlertCircle } from 'lucide-react';
import * as Knowledge from '../services/knowledgeService';

interface KnowledgeBaseViewProps {
  onBack: () => void;
}

type UploadStatus = 'idle' | 'uploading' | 'indexing' | 'done' | 'error';

interface UploadingFile {
  name: string;
  status: UploadStatus;
  error?: string;
}

const KnowledgeBaseView: React.FC<KnowledgeBaseViewProps> = ({ onBack }) => {
  const [documents, setDocuments] = useState<Array<{ name: string; displayName: string }>>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [uploadingFiles, setUploadingFiles] = useState<UploadingFile[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResult, setSearchResult] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    loadDocuments();
  }, []);

  const loadDocuments = async () => {
    setIsLoading(true);
    try {
      const docs = await Knowledge.listDocuments();
      setDocuments(docs);
    } catch (e) {
      console.error('Failed to load documents:', e);
    }
    setIsLoading(false);
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const fileArray = Array.from(files);

    setUploadingFiles(prev => [
      ...prev,
      ...fileArray.map(f => ({ name: f.name, status: 'uploading' as UploadStatus }))
    ]);

    for (const file of fileArray) {
      try {
        setUploadingFiles(prev =>
          prev.map(f => f.name === file.name ? { ...f, status: 'indexing' } : f)
        );

        await Knowledge.uploadDocument(file);

        setUploadingFiles(prev =>
          prev.map(f => f.name === file.name ? { ...f, status: 'done' } : f)
        );
      } catch (err: any) {
        setUploadingFiles(prev =>
          prev.map(f => f.name === file.name ? { ...f, status: 'error', error: err.message } : f)
        );
      }
    }

    await loadDocuments();

    setTimeout(() => {
      setUploadingFiles(prev => prev.filter(f => f.status !== 'done'));
    }, 3000);

    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleDelete = async (docName: string, displayName: string) => {
    if (!confirm(`Delete "${displayName}" from the knowledge base?`)) return;
    try {
      await Knowledge.deleteDocument(docName);
      setDocuments(prev => prev.filter(d => d.name !== docName));
    } catch (e) {
      console.error('Failed to delete document:', e);
    }
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;
    setIsSearching(true);
    setSearchResult('');
    try {
      const result = await Knowledge.queryKnowledgeBase(searchQuery);
      setSearchResult(result);
    } catch (err: any) {
      setSearchResult('Search failed: ' + err.message);
    }
    setIsSearching(false);
  };

  const getFileIcon = (fileName: string) => {
    const ext = fileName.split('.').pop()?.toLowerCase();
    if (ext === 'pdf') return '📄';
    if (ext === 'doc' || ext === 'docx') return '📝';
    if (ext === 'xls' || ext === 'xlsx' || ext === 'csv') return '📊';
    if (ext === 'txt' || ext === 'md') return '📃';
    return '📎';
  };

  const getStatusIcon = (status: UploadStatus) => {
    switch (status) {
      case 'uploading':
        return <Loader2 size={14} className="animate-spin text-pink-500" />;
      case 'indexing':
        return <Loader2 size={14} className="animate-spin text-yellow-500" />;
      case 'done':
        return <CheckCircle size={14} className="text-green-500" />;
      case 'error':
        return <AlertCircle size={14} className="text-red-500" />;
      default:
        return null;
    }
  };

  const getStatusText = (status: UploadStatus) => {
    switch (status) {
      case 'uploading': return 'Uploading...';
      case 'indexing': return 'Indexing...';
      case 'done': return 'Ready';
      case 'error': return 'Failed';
      default: return '';
    }
  };

  return (
    <div className="h-full flex flex-col bg-gray-50">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-100">
        <div className="flex items-center gap-3">
          <button onClick={onBack} className="p-2 -ml-2 text-gray-400 hover:text-gray-900 rounded-full hover:bg-gray-100">
            <ArrowLeft size={24} />
          </button>
          <div>
            <h1 className="text-xl font-bold text-gray-900">Knowledge Base</h1>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold">Barbie's Brain</p>
          </div>
        </div>
        <button
          onClick={() => fileInputRef.current?.click()}
          className="flex items-center gap-2 px-4 py-2 bg-pink-500 text-white text-sm font-semibold rounded-xl hover:bg-pink-600 active:scale-95 transition-all shadow-lg shadow-pink-200"
        >
          <Upload size={16} />
          Upload
        </button>
        <input
          ref={fileInputRef}
          type="file"
          multiple
          accept=".pdf,.doc,.docx,.txt,.csv,.xls,.xlsx,.md,.json"
          onChange={handleFileSelect}
          className="hidden"
        />
      </header>

      {uploadingFiles.length > 0 && (
        <div className="p-4 bg-pink-50 border-b border-pink-100 space-y-2">
          {uploadingFiles.map((file, idx) => (
            <div key={idx} className="flex items-center gap-3 text-sm">
              {getStatusIcon(file.status)}
              <span className="font-medium text-gray-700 truncate flex-1">{file.name}</span>
              <span className={`text-xs font-bold uppercase tracking-wider ${
                file.status === 'done' ? 'text-green-600' :
                file.status === 'error' ? 'text-red-600' :
                'text-pink-500'
              }`}>
                {getStatusText(file.status)}
              </span>
            </div>
          ))}
        </div>
      )}

      <div className="p-4 bg-white border-b border-gray-100">
        <form onSubmit={handleSearch} className="flex gap-2">
          <div className="flex-1 relative">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Ask a question about your documents..."
              className="w-full pl-10 pr-4 py-2.5 border border-gray-200 rounded-xl text-sm focus:outline-none focus:border-pink-300 focus:ring-2 focus:ring-pink-100"
            />
          </div>
          <button
            type="submit"
            disabled={isSearching || !searchQuery.trim()}
            className="px-4 py-2.5 bg-gray-900 text-white text-sm font-semibold rounded-xl disabled:opacity-50 hover:bg-gray-800"
          >
            {isSearching ? <Loader2 size={16} className="animate-spin" /> : 'Ask'}
          </button>
        </form>
        {searchResult && (
          <div className="mt-3 p-4 bg-pink-50 rounded-xl border border-pink-100">
            <p className="text-[10px] font-bold text-pink-500 uppercase tracking-widest mb-1">Barbie's Answer</p>
            <p className="text-sm text-gray-800 whitespace-pre-wrap leading-relaxed">{searchResult}</p>
          </div>
        )}
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-2">
        <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">
          Uploaded Documents ({documents.length})
        </h3>

        {isLoading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 size={24} className="animate-spin text-pink-400" />
          </div>
        ) : documents.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16 text-gray-400">
            <FileText size={48} strokeWidth={1} className="mb-3 text-gray-300" />
            <p className="font-medium">No documents yet</p>
            <p className="text-xs mt-1">Upload files to train Barbie</p>
          </div>
        ) : (
          documents.map((doc) => (
            <div key={doc.name} className="flex items-center gap-3 p-3 bg-white rounded-xl border border-gray-100 shadow-sm group">
              <div className="text-2xl flex-shrink-0">
                {getFileIcon(doc.displayName)}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold text-gray-900 truncate">{doc.displayName}</p>
                <p className="text-[10px] text-gray-400 truncate">{doc.name}</p>
              </div>
              <button
                onClick={() => handleDelete(doc.name, doc.displayName)}
                className="p-2 text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
              >
                <Trash2 size={16} />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default KnowledgeBaseView;

import { GoogleGenAI } from "@google/genai";

const STORAGE_KEY = 'trinaos_knowledge_docs';

interface DocumentMetadata {
  name: string;
  displayName: string;
  type: string;
  uploadedAt: number;
}

export const listDocuments = async (): Promise<DocumentMetadata[]> => {
  const stored = localStorage.getItem(STORAGE_KEY);
  return stored ? JSON.parse(stored) : [];
};

export const uploadDocument = async (file: File): Promise<DocumentMetadata> => {
  // Mock upload delay
  await new Promise(resolve => setTimeout(resolve, 1500));

  const docs = await listDocuments();
  const newDoc: DocumentMetadata = {
    name: `doc_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
    displayName: file.name,
    type: file.type,
    uploadedAt: Date.now()
  };

  localStorage.setItem(STORAGE_KEY, JSON.stringify([...docs, newDoc]));
  return newDoc;
};

export const deleteDocument = async (name: string): Promise<void> => {
  const docs = await listDocuments();
  localStorage.setItem(STORAGE_KEY, JSON.stringify(docs.filter(d => d.name !== name)));
};

export const queryKnowledgeBase = async (question: string): Promise<string> => {
  const apiKey = process.env.API_KEY || '';
  const ai = new GoogleGenAI({ apiKey });

  const docs = await listDocuments();
  if (docs.length === 0) {
    return "I don't have any business documents uploaded yet. Please upload some files so I can give you accurate information about your daycare.";
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `User Question: ${question}\n\nContext: The user has uploaded ${docs.length} documents including ${docs.map(d => d.displayName).join(', ')}. Since this is a lightweight version, I'm simulating searching these documents. Provide a helpful, professional, and strategic answer (Barbie persona) based on the context of a daycare owner named Trina in Louisville.`,
      config: {
        systemInstruction: "You are Barbie, Trina's EOA (Executive Orchestrator). You have access to her business knowledge base. Be concise, strategic, and professional."
      }
    });

    return response.text || "I processed your request but couldn't find a specific answer in the current logs.";
  } catch (error) {
    console.error("Knowledge Query Error:", error);
    return "I'm having trouble accessing my internal data right now. Let's try again in a moment.";
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Dashboard from './components/Dashboard';
import TasksView from './components/TasksView';
import FinanceView from './components/FinanceView';
import WeeklyResetView from './components/WeeklyResetView';
import BrainDumpView from './components/BrainDumpView';
import CalendarView from './components/CalendarView';
import KnowledgeBaseView from './components/KnowledgeBaseView';
import * as Knowledge from './services/knowledgeService';
import { AppMode, Task, Transaction, CalendarEvent, BrainDumpResult } from './types';
import * as Storage from './services/storageService';
import { useLive } from './hooks/useLive';
import { BrainCircuit, Activity } from 'lucide-react';
import * as Gmail from './services/gmailService';
import * as Firestore from './services/firestoreService';
import * as Auth from './services/authService';

const GMAIL_CLIENT_ID = 'YOUR_CLIENT_ID.apps.googleusercontent.com';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.DASHBOARD);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [timerSeconds, setTimerSeconds] = useState<number | null>(null);
  const [initialTimerValue, setInitialTimerValue] = useState<number | null>(null);
  const [notifications, setNotifications] = useState<any[]>([]);
  const [isGmailConnected, setIsGmailConnected] = useState(false);
  const [isDbConnected, setIsDbConnected] = useState(true);
  const [isCloudConnected, setIsCloudConnected] = useState(false);

  const timerIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    try {
      setTasks(Storage.getTasks());
      setTransactions(Storage.getTransactions());
      setEvents(Storage.getEvents());
      setIsDbConnected(true);
    } catch (e) {
      console.error("Database connection error:", e);
      setIsDbConnected(false);
    }

    Gmail.initGmailAuth(GMAIL_CLIENT_ID).catch(console.error);

    const checkToken = setInterval(() => {
      if (Gmail.getAccessToken()) {
        setIsGmailConnected(true);
        clearInterval(checkToken);
      }
    }, 1000);

    Auth.signIn("test@barbie.com", "testpass123")
      .then(({ token, uid }) => {
        Firestore.setAuth(token, uid);
        setIsCloudConnected(true);
      })
      .catch((err) => {
        setIsCloudConnected(false);
      });

    return () => clearInterval(checkToken);
  }, []);

  useEffect(() => {
    const checkNotifications = () => {
      const now = new Date();
      const todayStr = now.toISOString().split('T')[0];
      const currentTime = `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;

      const todayEvents = events.filter(e => e.date === todayStr && e.time);
      const upcoming = todayEvents.filter(e => {
        if (!e.time) return false;
        const [eH, eM] = e.time.split(':').map(Number);
        const [cH, cM] = currentTime.split(':').map(Number);
        const eventMins = eH * 60 + eM;
        const currentMins = cH * 60 + cM;
        const diff = eventMins - currentMins;
        return diff > 0 && diff <= 15;
      });

      if (upcoming.length > 0) {
        setNotifications(upcoming.map(e => ({
          id: e.id,
          type: 'event',
          title: e.title,
          message: `Coming up at ${e.time}`,
          date: e.date,
        })));
      }
    };

    const interval = setInterval(checkNotifications, 60000);
    return () => clearInterval(interval);
  }, [events]);

  useEffect(() => {
    if (timerSeconds !== null && timerSeconds > 0) {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      timerIntervalRef.current = window.setInterval(() => {
        setTimerSeconds(prev => (prev !== null && prev > 0) ? prev - 1 : 0);
      }, 1000);
    } else if (timerSeconds === 0) {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      setTimerSeconds(null);
      setInitialTimerValue(null);
      alert("EOA Alert: Trina, your timer has expired.");
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [timerSeconds]);

  const handleGmailConnect = () => {
    Gmail.requestGmailToken();
  };

  const handleToolCall = useCallback(async (name: string, args: any) => {
    if (name === 'changeView') {
      const mode = args.view as AppMode;
      if (mode) setCurrentMode(mode);
      return { success: true };
    }
    if (name === 'setTimer') {
      const secs = Math.round(args.minutes * 60);
      setTimerSeconds(secs);
      setInitialTimerValue(secs);
      return { success: true, message: `Timer set for ${args.minutes} minutes` };
    }
    if (name === 'stopTimer') {
      setTimerSeconds(null);
      setInitialTimerValue(null);
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      return { success: true, message: "Timer stopped and cleared." };
    }

    if (name === 'list_emails') {
      if (!isGmailConnected) return { error: "Gmail not connected. Please ask Trina to tap 'Connect Gmail'." };
      try {
        const emails = await Gmail.listMessages(args.count || 5);
        return { emails, status: "Retrieved unread emails from Louisville HQ inbox." };
      } catch (e: any) {
        return { error: e.message };
      }
    }
    if (name === 'reply_to_email') {
      if (!isGmailConnected) return { error: "Gmail not connected." };
      try {
        await Gmail.replyToEmail(args.threadId, args.to, args.subject, args.body);
        return { success: true, message: "Reply sent successfully." };
      } catch (e: any) {
        return { error: e.message };
      }
    }
    if (name === 'archive_email') {
      try {
        await Gmail.archiveMessage(args.id);
        return { success: true, message: "Email archived." };
      } catch (e: any) {
        return { error: e.message };
      }
    }

    if (name === 'addTask') {
       const newTask = Storage.addTask({
         title: args.title,
         priority: (args.priority as any) || 'Medium',
         status: 'Todo' as any,
         delegatable: false,
         deadline: args.deadline
       });
       setTasks(prev => [...prev, newTask]);
       return { success: true, task: newTask };
    }

    if (name === 'addEvent') {
      const newEvent = Storage.addEvent({
        title: args.title,
        date: args.date || new Date().toISOString().split('T')[0],
        time: args.time,
        endTime: args.endTime,
        description: args.description || '',
        category: args.category || 'meeting',
        recurring: args.recurring || 'none',
      });
      setEvents(prev => [...prev, newEvent]);
      return { success: true, event: newEvent };
    }

    if (name === 'getEvents') {
      const days = args.days || 7;
      const upcoming = Storage.getUpcomingEvents(days);
      return { events: upcoming, count: upcoming.length };
    }

    if (name === 'deleteEvent') {
      Storage.deleteEvent(args.eventId);
      setEvents(Storage.getEvents());
      return { success: true, message: "Event deleted." };
    }

    if (name === 'check_database_health') {
      return { status: "Online", healthy: true, cloudStatus: isCloudConnected ? "Connected" : "Disconnected" };
    }

    if (name === 'getData') {
      return { 
        tasks: Storage.getTasks(), 
        finance: Storage.getTransactions(),
        events: Storage.getUpcomingEvents(7),
        timeZone: "America/New_York",
        gmailStatus: isGmailConnected ? "Connected" : "Disconnected",
        databaseStatus: isDbConnected ? "Connected" : "Disconnected"
      };
    }

    if (name === 'save_memory') {
      if (!isCloudConnected) return { error: "Cloud not connected." };
      try {
        const id = await Firestore.saveMemory(args.text, args.tags || ["voice"]);
        return { success: true, memoryId: id };
      } catch (e: any) {
        return { error: e.message };
      }
    }

    if (name === 'recall_memories') {
      if (!isCloudConnected) return { error: "Cloud not connected." };
      try {
        const memories = await Firestore.getMemories(args.count || 10);
        return { memories, count: memories.length };
      } catch (e: any) {
        return { error: e.message };
      }
    }

    if (name === 'search_knowledge') {
      try {
        const answer = await Knowledge.queryKnowledgeBase(args.question);
        return { answer, source: "knowledge_base" };
      } catch (e: any) {
        return { error: e.message };
      }
    }

    if (name === 'sync_to_cloud') {
      if (!isCloudConnected) return { error: "Cloud not connected." };
      try {
        await Firestore.syncDataToFirestore(tasks, transactions);
        return { success: true, message: "Synced." };
      } catch (e: any) {
        return { error: e.message };
      }
    }

    return { success: false };
  }, [isGmailConnected, isDbConnected, isCloudConnected, tasks, transactions, events]);

  const { connect, disconnect, isConnected, isSpeaking, volume } = useLive({
    onToolCall: handleToolCall
  });

  const handleProcessBrainDumpResults = (result: BrainDumpResult) => {
    result.tasks.forEach(t => {
      if (t.title) {
        const nt = Storage.addTask({
          title: t.title,
          priority: (t.priority as any) || 'Medium',
          status: 'Todo' as any,
          delegatable: t.delegatable || false,
          deadline: t.deadline
        });
        setTasks(prev => [...prev, nt]);
      }
    });

    result.transactions.forEach(tx => {
      if (tx.amount && tx.category) {
        const ntx = Storage.addTransaction({
          type: (tx.type as any) || 'Expense',
          amount: tx.amount,
          category: tx.category,
          description: tx.description || tx.category,
          date: tx.date || new Date().toISOString().split('T')[0]
        });
        setTransactions(prev => [...prev, ntx]);
      }
    });
  };

  const renderContent = () => {
    switch (currentMode) {
      case AppMode.TASKS:
        return <TasksView tasks={tasks} events={events} onAddTask={(t) => setTasks(prev => [...prev, Storage.addTask(t)])} onUpdateTask={(t) => { Storage.updateTask(t); setTasks(Storage.getTasks()); }} onBack={() => setCurrentMode(AppMode.DASHBOARD)} />;
      case AppMode.FINANCE:
        return <FinanceView transactions={transactions} onAddTransaction={(tx) => setTransactions(prev => [...prev, Storage.addTransaction(tx)])} onBack={() => setCurrentMode(AppMode.DASHBOARD)} />;
      case AppMode.WEEKLY_RESET:
        return <WeeklyResetView tasks={tasks} transactions={transactions} onBack={() => setCurrentMode(AppMode.DASHBOARD)} />;
      case AppMode.BRAIN_DUMP:
        return <BrainDumpView onProcessResults={handleProcessBrainDumpResults} onBack={() => setCurrentMode(AppMode.DASHBOARD)} />;
      case AppMode.CALENDAR:
        return <CalendarView events={events} onAddEvent={(e) => { const ne = Storage.addEvent(e); setEvents(prev => [...prev, ne]); }} onDeleteEvent={(id) => { Storage.deleteEvent(id); setEvents(Storage.getEvents()); }} onBack={() => setCurrentMode(AppMode.DASHBOARD)} />;
      case AppMode.KNOWLEDGE_BASE:
        return <KnowledgeBaseView onBack={() => setCurrentMode(AppMode.DASHBOARD)} />;  
      default:
        return (
          <Dashboard 
            onNavigate={setCurrentMode}
            isConnected={isConnected}
            isSpeaking={isSpeaking}
            volume={volume}
            onToggleVoice={() => isConnected ? disconnect() : connect()}
            timer={timerSeconds}
            initialTimerValue={initialTimerValue}
            notificationCount={notifications.length}
            isGmailConnected={isGmailConnected}
            isDbConnected={isDbConnected}
            onConnectGmail={handleGmailConnect}
          />
        );
    }
  };

  return (
    <div className="min-h-screen bg-[#fff5f7] flex flex-col mx-auto max-w-2xl shadow-2xl overflow-hidden relative border-x border-pink-100">
      <main className="flex-1 overflow-hidden relative">
        {renderContent()}
      </main>

      {currentMode !== AppMode.DASHBOARD && isConnected && (
        <div 
           className="fixed bottom-10 right-10 z-50 cursor-pointer animate-float"
           onClick={() => setCurrentMode(AppMode.DASHBOARD)}
        >
          <div className={`w-24 h-24 rounded-full flex items-center justify-center shadow-[0_15px_40px_-5px_rgba(244,114,182,0.6)] border-4 border-white ${isSpeaking ? 'bg-pink-600' : 'bg-pink-500'}`}>
             {isSpeaking ? <Activity className="text-white w-12 h-12" /> : <BrainCircuit className="text-white w-12 h-12" />}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

