        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{
            functionDeclarations: [
              /* Use correct Type enum for function parameters */
              { name: "changeView", parameters: { type: Type.OBJECT, properties: { view: { type: Type.STRING, enum: ["DASHBOARD", "TASKS", "FINANCE", "WEEKLY_RESET", "BRAIN_DUMP", "CALENDAR"] } } } },
              { name: "addTask", parameters: { type: Type.OBJECT, properties: { title: { type: Type.STRING }, priority: { type: Type.STRING }, deadline: { type: Type.STRING, description: "YYYY-MM-DD format" } }, required: ["title"] } },
              { name: "addTransaction", parameters: { type: Type.OBJECT, properties: { type: { type: Type.STRING }, amount: { type: Type.NUMBER }, category: { type: Type.STRING } } } },
              { name: "setTimer", parameters: { type: Type.OBJECT, properties: { minutes: { type: Type.NUMBER } }, required: ["minutes"] } },
              { name: "stopTimer", parameters: { type: Type.OBJECT, properties: {} } },
              { name: "list_emails", parameters: { type: Type.OBJECT, properties: { count: { type: Type.NUMBER } } } },
              { name: "reply_to_email", parameters: { type: Type.OBJECT, properties: { threadId: { type: Type.STRING }, to: { type: Type.STRING }, subject: { type: Type.STRING }, body: { type: Type.STRING } }, required: ["threadId", "to", "subject", "body"] } },
              { name: "archive_email", parameters: { type: Type.OBJECT, properties: { id: { type: Type.STRING } }, required: ["id"] } },
              { name: "check_database_health", parameters: { type: Type.OBJECT, properties: {} } },
