                <p className="text-[10px] font-medium text-gray-400 truncate tracking-tight">{doc.name}</p>
              </div>
              <button
                onClick={() => handleDelete(doc.name, doc.displayName, doc.id)}
                className="p-2.5 text-gray-200 hover:text-red-500 hover:bg-red-50 rounded-xl opacity-0 group-hover:opacity-100 transition-all"
              >
                <Trash2 size={18} />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

