import { GoogleGenAI } from "@google/genai";

const STORAGE_KEY = 'trinaos_knowledge_docs';

interface DocumentMetadata {
  id: string;
  name: string;
  displayName: string;
  type: string;
  uploadedAt: number;
}

export const listDocuments = async (): Promise<DocumentMetadata[]> => {
  const stored = localStorage.getItem(STORAGE_KEY);
  return stored ? JSON.parse(stored) : [];
};

export const uploadDocument = async (file: File): Promise<DocumentMetadata> => {
  // Simulate network latency for Barbie's indexing process
  await new Promise(resolve => setTimeout(resolve, 1200));

  const docs = await listDocuments();
  const newDoc: DocumentMetadata = {
    id: `doc_${Date.now()}`,
    name: `ref_${Math.random().toString(36).substr(2, 9)}`,
    displayName: file.name,
    type: file.type || 'application/octet-stream',
    uploadedAt: Date.now()
  };

  const updated = [...docs, newDoc];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  return newDoc;
};

export const deleteDocument = async (name: string, id?: string): Promise<void> => {
  const docs = await listDocuments();
  // Filter by id primarily, then by name as fallback
  const filtered = docs.filter(d => (id ? d.id !== id : d.name !== name));
  localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));
};

export const queryKnowledgeBase = async (question: string): Promise<string> => {
  const apiKey = process.env.API_KEY || '';
  if (!apiKey) {
    throw new Error("API Key is missing from the environment configuration.");
  }

  const ai = new GoogleGenAI({ apiKey });
  const docs = await listDocuments();

  if (docs.length === 0) {
    return "Your knowledge vault is currently empty, Trina. Upload some business documents or policies so I can analyze them for you.";
  }

  try {
    const docContext = docs.map(d => d.displayName).join(', ');
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Trina's Question: "${question}"\n\nContext: Trina is the owner of a daycare in Louisville. She has uploaded the following documents to her knowledge vault: ${docContext}. Simulate searching these documents and provide a professional, strategic, and concise answer in the Barbie persona.`,
      config: {
        systemInstruction: "You are Barbie, Trina's Executive AI Orchestrator (EOA). You have deep access to her business knowledge vault. Be professional, direct, and helpful. Use a sharp, high-competence tone."
      }
    });

    return response.text || "I've reviewed the vault but couldn't find a definitive answer to that specific question.";
  } catch (error) {
    console.error("Knowledge Query Error:", error);
    return "I'm having a momentary sync issue with the knowledge vault. Let me try re-indexing and you can ask again in a second.";
  }
};

